-- Schema for Domain: valuation | Business: Real Estate | Version: v1_mvm
-- Generated on: 2026-05-02 05:06:39

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `real_estate_ecm`.`valuation` COMMENT 'Manages property appraisals, BPOs, CMAs, and DCF-based valuations. Stores CAP rates, NOI inputs, IRR/NPV outputs, GAV/NAV calculations, and Argus Enterprise model references. Tracks appraisal history, certified appraiser credentials (Appraisal Institute), IVSC-compliant methodology metadata, and market value assessments supporting investment decision-making and financial reporting.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`appraisal` (
    `appraisal_id` BIGINT COMMENT 'Unique system-generated identifier for the formal property appraisal engagement record. Primary key for the appraisal data product.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: Appraisals express concluded value per square foot or square meter; the area unit of measure drives value_psf calculations and cross-border comparability. Every appraisal engagement specifies the meas',
    `assessment_id` BIGINT COMMENT 'Foreign key linking to compliance.assessment. Business justification: Appraisal engagements are subject to compliance assessments by state appraisal boards, lender QC programs, and USPAP review panels. Linking appraisal to the governing compliance assessment enables tra',
    `asset_id` BIGINT COMMENT 'Reference to the subject property being appraised. Links the appraisal engagement to the master property record in the portfolio.',
    `brokerage_deal_id` BIGINT COMMENT 'Foreign key linking to brokerage.brokerage_deal. Business justification: Appraisals are ordered as part of deal due diligence (lender requirement, buyer contingency). The deal that triggered the appraisal engagement must be traceable for deal pipeline reporting and commiss',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: Appraisal fees are budgeted line items. Linking appraisal to finance_budget supports budget vs. actual tracking of valuation costs, a standard real estate accounting control required for annual operat',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: Appraisal comparable selection, cap rate benchmarks, and market rent conclusions are building-class-specific (Class A vs B vs C). A domain expert would expect every appraisal to reference the standard',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Appraisals are conducted at the building level — the physical inspection, GBA measurement, condition rating, and USPAP scope of work all reference a specific building record. A commercial RE appraiser',
    `cap_rate_benchmark_id` BIGINT COMMENT 'Foreign key linking to valuation.cap_rate_benchmark. Business justification: appraisal stores a concluded cap_rate. This rate should be supported by market benchmark data for USPAP/IVSC compliance and investment committee review. Adding cap_rate_benchmark_id links the appraisa',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Appraisals of properties under development or renovation must reference active permits (building permits, certificates of occupancy) as they directly affect value type (as-is vs. as-complete) and hypo',
    `construction_type_id` BIGINT COMMENT 'Foreign key linking to reference.construction_type. Business justification: USPAP/IVSC cost approach requires construction type classification (wood frame, masonry, steel) to determine replacement cost new and depreciation. Appraisers document this in every appraisal report; ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Appraisal engagement fees are coded to cost centers for GL posting and internal cost allocation. Real estate controllers track valuation costs by cost center for budget variance analysis. No existing ',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: All appraisal financial outputs (concluded_market_value, engagement_fee, value_range_low/high) are currency-denominated. Normalizing the plain currency_code column to a FK enables multi-currency portf',
    `debt_instrument_id` BIGINT COMMENT 'Foreign key linking to finance.debt_instrument. Business justification: Loan underwriting and covenant compliance require appraisals tied to specific debt instruments. Lenders order appraisals at origination and refinancing; the appraisal must be traceable to the loan it ',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: Construction loan underwriting requires appraisals tied directly to the development project for as-complete and as-stabilized valuations. Lenders and equity investors pull all appraisals by dev_projec',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: Appraisal comparable selection, cap rate benchmarks, and market conditions analysis are submarket-specific. A domain expert would expect every appraisal to reference the geographic hierarchy for subma',
    `green_certification_id` BIGINT COMMENT 'Foreign key linking to compliance.green_certification. Business justification: Green building valuation is a named appraisal specialty: LEED/BREEAM certifications directly affect income, expense, and cap rate assumptions. Appraisers must reference the active certification record',
    `industry_classification_id` BIGINT COMMENT 'Foreign key linking to reference.industry_classification. Business justification: Commercial appraisals classify the primary tenant industry (NAICS/SIC) to benchmark market rents, assess re-leasing risk, and support income approach. Lenders and investors require tenant industry cla',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction. Business justification: Appraisals are jurisdiction-specific: appraiser licensing, USPAP enforcement, and regulatory filing requirements vary by jurisdiction. Compliance teams and lenders require jurisdiction traceability on',
    `lease_type_id` BIGINT COMMENT 'Foreign key linking to reference.lease_type. Business justification: Appraisals of income-producing properties classify the predominant lease structure (NNN, gross, modified gross) which directly determines NOI calculation methodology and cap rate selection. USPAP inco',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Appraisals are recorded against a specific accounting ledger (GAAP fair value vs. tax basis). Required for ASC 820 fair value hierarchy disclosures and IFRS 13 compliance in real estate fund accountin',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Appraisals are commissioned by and delivered to specific legal entities for REIT financial reporting, ASC 820 fair value hierarchy disclosures, and audit purposes. The existing `intended_user` and `cl',
    `listing_agreement_id` BIGINT COMMENT 'Foreign key linking to brokerage.listing_agreement. Business justification: Pre-listing appraisals are ordered as part of listing agreement execution to establish defensible asking price. Listing brokers commission appraisals under the listing agreement. This link supports li',
    `listing_id` BIGINT COMMENT 'Foreign key linking to brokerage.listing. Business justification: Appraisals are routinely commissioned to validate or support a specific listing price — by sellers, lenders, or buyers during active marketing. Linking appraisal to listing enables listing price valid',
    `market_research_id` BIGINT COMMENT 'Foreign key linking to marketing.market_research. Business justification: Appraisers cite market research reports to support market conditions narratives, cap rate selection, and rent assumptions in USPAP-compliant appraisal reports. A real estate appraiser would expect the',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to reference.market_segment. Business justification: Appraisals are commissioned for specific investment strategies (core, value-add, opportunistic) that determine the intended use, discount rate assumptions, and investor profile. Linking to market_segm',
    `market_survey_id` BIGINT COMMENT 'Foreign key linking to marketing.market_survey. Business justification: Appraisers directly reference market surveys for vacancy rates, asking rents, and absorption data used in the market conditions section of appraisal reports. A valuation analyst would link the apprais',
    `noi_statement_id` BIGINT COMMENT 'Foreign key linking to finance.noi_statement. Business justification: Income approach appraisals use NOI as the primary value driver. Linking to the authoritative NOI statement provides an audit trail for the NOI figure used in the appraisal, supporting USPAP scope-of-w',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to property.parcel. Business justification: Appraisals require parcel data (APN, legal description, zoning, lot size) as direct inputs to the cost approach land valuation and highest-and-best-use analysis. A real estate appraiser always referen',
    `prior_appraisal_id` BIGINT COMMENT 'Self-referencing identifier linking this appraisal to the most recent prior appraisal for the same property. Enables appraisal history tracking, value trend analysis, and year-over-year valuation movement reporting.',
    `property_ownership_interest_id` BIGINT COMMENT 'Foreign key linking to property.property_ownership_interest. Business justification: USPAP requires appraisers to identify the property rights being appraised (fee simple, leasehold, partial interest). Linking appraisal to property_ownership_interest supports interest-specific valuati',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: Appraisal methodology, comparable selection criteria, cap rate benchmarks, and USPAP scope of work are all property-type-specific. A domain expert would expect every appraisal to reference the standar',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Appraisals are commissioned to satisfy specific regulatory obligations (FIRREA, Dodd-Frank appraisal independence, state licensing laws). Compliance teams track which regulatory obligation each apprai',
    `remediation_action_id` BIGINT COMMENT 'Foreign key linking to compliance.remediation_action. Business justification: Contaminated property appraisals require reference to active remediation actions to determine as-is vs. as-remediated value. The Appraisal Institutes guidance on environmentally contaminated properti',
    `reporting_period_id` BIGINT COMMENT 'Foreign key linking to finance.reporting_period. Business justification: Appraisals are conducted as of value dates aligned with financial reporting periods (quarter-end, year-end). Linking to reporting_period enables automated inclusion in period-end fair value disclosure',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Commercial appraisals for leasehold interests and partial-floor valuations target specific leasable spaces. USPAP Standard 1 requires identification of the property rights appraised; space-level appra',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: Appraisals classify the subject propertys space use (office, retail, industrial) to select appropriate income approach assumptions and comparable sales. This is a primary filter in every USPAP-compli',
    `title_record_id` BIGINT COMMENT 'Foreign key linking to property.title_record. Business justification: USPAP Standard 1 requires appraisers to review title records as part of scope of work. Linking appraisal to title_record supports automated title-to-value reconciliation in lender underwriting workflo',
    `transaction_type_id` BIGINT COMMENT 'Foreign key linking to reference.transaction_type. Business justification: Appraisals are commissioned for specific transaction types (sale, refinance, estate, litigation) which determines the standard of value (market value vs. investment value) and USPAP scope of work. Eng',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Residential appraisals (condominiums, co-ops, single-family units) are conducted at the unit level. The appraisal inspection, bedroom/bathroom count, and concluded value reference a specific unit. Mor',
    `violation_id` BIGINT COMMENT 'Foreign key linking to compliance.violation. Business justification: Appraisals of properties with active compliance violations (zoning, building code, environmental) must disclose and quantify the value impact. State appraisal boards also track USPAP violations agains',
    `zoning_code_id` BIGINT COMMENT 'Foreign key linking to reference.zoning_code. Business justification: USPAP requires highest and best use analysis, which is constrained by zoning. The permitted uses, FAR, density, and conditional uses from zoning_code directly inform the legally permissible use determ',
    `appraisal_status` STRING COMMENT 'Current lifecycle state of the appraisal engagement. Tracks progression from initial order through field work, internal review, and final delivery or rejection. Supports SLA monitoring and workflow management in Yardi Voyager and Argus Enterprise.. Valid values are `ordered|in-progress|review|completed|rejected|cancelled`',
    `appraisal_type` STRING COMMENT 'Classification of the appraisal scope and inspection methodology. Full appraisals involve complete interior/exterior inspection; limited, desktop, and drive-by involve reduced scope. Retrospective appraisals value a property as of a historical date. [ENUM-REF-CANDIDATE: full|limited|desktop|drive-by|retrospective|automated — promote to reference product]. Valid values are `full|limited|desktop|drive-by|retrospective`',
    `appraiser_credential` STRING COMMENT 'Professional designation held by the assigned appraiser at the time of the engagement. MAI and SRA are Appraisal Institute designations for commercial and residential specialists respectively. AI-GRS and AI-RRS are review designations. MRICS is the Royal Institution of Chartered Surveyors designation. Required for USPAP and IVSC compliance.. Valid values are `MAI|SRA|AI-GRS|AI-RRS|MRICS|ASA`',
    `appraiser_license_number` STRING COMMENT 'State-issued appraiser license or certification number for the assigned appraiser. Required for regulatory compliance and lender review. Confidential business record used to verify appraiser eligibility on each engagement.',
    `argus_model_reference` STRING COMMENT 'The unique identifier of the Argus Enterprise cash flow model associated with this appraisal engagement. Enables direct traceability between the appraisal record and the underlying DCF model file for audit and replication purposes.',
    `cap_rate` DECIMAL(18,2) COMMENT 'The overall capitalization rate applied in the income capitalization approach, expressed as a decimal (e.g., 0.0550 for 5.50%). Derived from market comparable sales and used to convert Net Operating Income (NOI) into an indicated value. Key input for Argus Enterprise DCF models.',
    `client_reference` STRING COMMENT 'The clients internal reference number or loan number associated with this appraisal order. Used by lenders, investment managers, or asset managers to cross-reference the appraisal with their own systems (e.g., MRI Software investment records).',
    `concluded_market_value` DECIMAL(18,2) COMMENT 'The appraisers final concluded value opinion for the subject property as of the effective value date, expressed in the engagement currency. This is the primary output of the appraisal engagement and feeds NAV/GAV calculations, LTV ratios, and DSCR analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the appraisal engagement record was first created in the system. Supports audit trail requirements under SOX financial controls and data lineage tracking in the Databricks Silver Layer.',
    `discount_rate` DECIMAL(18,2) COMMENT 'The risk-adjusted discount rate applied to future cash flows in the DCF analysis, expressed as a decimal. Reflects the required rate of return for the asset class, location, and risk profile. Key Argus Enterprise model input.',
    `engagement_date` DATE COMMENT 'The date the appraisal was formally ordered and the engagement letter was executed. Marks the start of the appraisal lifecycle and the SLA turnaround clock.',
    `engagement_fee` DECIMAL(18,2) COMMENT 'The agreed fee payable to the appraisal firm for the engagement, in the engagement currency. Recorded for accounts payable processing in Yardi Voyager and budget tracking against the valuation OPEX budget.',
    `engagement_letter_ref` STRING COMMENT 'Document reference number or DocuSign CLM contract ID for the executed engagement letter between the client and the appraisal firm. Provides legal traceability and supports contract lifecycle management.',
    `engagement_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to the appraisal engagement at the time of ordering. Used for cross-referencing with the engagement letter, Argus Enterprise, and Yardi Voyager fixed asset records.',
    `firm_name` STRING COMMENT 'The name of the external appraisal firm engaged to perform the appraisal. Supports vendor management, conflict-of-interest tracking, and appraiser rotation policies required by lenders and regulators.',
    `holding_period_years` STRING COMMENT 'The number of years in the Discounted Cash Flow (DCF) analysis projection period. Typically 10 years for commercial real estate. Defines the time horizon over which cash flows are modeled in Argus Enterprise.',
    `inspection_date` DATE COMMENT 'The date the appraiser physically inspected the subject property. Required disclosure in USPAP-compliant reports. For desktop or drive-by appraisals, this field may be null or reflect the date of external observation.',
    `intended_user` STRING COMMENT 'The party or parties identified in the engagement letter as the intended user(s) of the appraisal report (e.g., lender name, investment committee, asset manager). USPAP requires explicit identification of intended users to define the scope of work.',
    `irr` DECIMAL(18,2) COMMENT 'The discount rate at which the net present value of projected cash flows equals zero, as concluded in the DCF analysis. Expressed as a decimal (e.g., 0.0850 for 8.50%). Key output metric for investment decision-making and portfolio performance benchmarking.',
    `ivsc_compliant` BOOLEAN COMMENT 'Indicates whether the appraisal methodology and report comply with International Valuation Standards (IVS) as published by the IVSC. Required for cross-border investment reporting and IFRS-based financial statements.',
    `methodology` STRING COMMENT 'The primary valuation methodology applied in the appraisal. Sales Comparison, Income Capitalization (direct CAP rate), Cost Approach, Discounted Cash Flow (DCF), Broker Price Opinion (BPO), or Comparative Market Analysis (CMA). USPAP and IVSC require disclosure of methodology in the report.. Valid values are `sales-comparison|income-capitalization|cost|dcf|bpo|cma`',
    `noi` DECIMAL(18,2) COMMENT 'The stabilized Net Operating Income used as the primary income input in the income capitalization approach. Calculated as Effective Gross Income (EGI) less operating expenses, excluding debt service and capital expenditures. Sourced from Yardi Voyager or Argus Enterprise.',
    `npv` DECIMAL(18,2) COMMENT 'The net present value of projected future cash flows discounted at the required rate of return, as output from the DCF model. Positive NPV indicates value creation above the required return threshold. Sourced from Argus Enterprise DCF model.',
    `purpose` STRING COMMENT 'The intended use of the appraisal report as stated in the engagement letter. Drives the applicable standard of value and methodology selection. Common purposes include financing (LTV/DSCR support), disposition, insurance replacement cost, tax appeal, portfolio review (NAV/GAV), and litigation support.. Valid values are `financing|disposition|insurance|tax-appeal|portfolio-review|litigation`',
    `report_delivery_date` DATE COMMENT 'The date the completed appraisal report was delivered to the client or intended user. Used to measure SLA turnaround compliance from engagement date to delivery.',
    `report_document_ref` STRING COMMENT 'Document management system reference or DocuSign CLM document ID for the final appraisal report deliverable. Enables direct retrieval of the report PDF or narrative document from the document repository.',
    `report_type` STRING COMMENT 'The format of the appraisal report deliverable. URAR (Uniform Residential Appraisal Report) is the standard Fannie Mae/Freddie Mac form for residential properties. Narrative reports provide full written analysis. Restricted and Summary reports are abbreviated formats per USPAP.. Valid values are `URAR|narrative|restricted|summary`',
    `report_version` STRING COMMENT 'Indicates the hypothetical condition or premise of the concluded value. As-Is reflects current physical and economic condition. As-Stabilized assumes the property reaches stabilized occupancy. As-Complete assumes a development or renovation project is finished.. Valid values are `as-is|as-stabilized|as-complete`',
    `review_date` DATE COMMENT 'The date the appraisal review was completed by the review appraiser. Tracks the review stage of the appraisal lifecycle and supports SLA measurement for the review turnaround.',
    `review_outcome` STRING COMMENT 'The outcome of the internal or external appraisal review. Approved reports proceed to final use; rejected or revision-required reports are returned to the appraiser. Drives the status lifecycle transition.. Valid values are `approved|approved-with-conditions|rejected|revision-required`',
    `sla_turnaround_days` STRING COMMENT 'The contractually agreed maximum number of calendar days from engagement date to report delivery. Used to monitor appraiser performance and manage investment decision timelines.',
    `terminal_cap_rate` DECIMAL(18,2) COMMENT 'The reversion or terminal capitalization rate applied to the projected NOI at the end of the DCF holding period to estimate the residual/reversion value. Expressed as a decimal. Standard Argus Enterprise DCF model parameter.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when the appraisal engagement record was last modified. Supports change data capture (CDC) in the Databricks Lakehouse Silver Layer and audit trail requirements under SOX.',
    `uspap_compliant` BOOLEAN COMMENT 'Indicates whether the appraisal was performed in compliance with the Uniform Standards of Professional Appraisal Practice (USPAP) as promulgated by The Appraisal Foundation. Required for federally related transactions under FIRREA.',
    `value_date` DATE COMMENT 'The effective date of the concluded value opinion, which may differ from the report delivery date. For retrospective appraisals, this is a historical date. Critical for FASB ASC 820 fair value measurement and IFRS 16 lease accounting purposes.',
    `value_range_high` DECIMAL(18,2) COMMENT 'The upper bound of the appraisers value range opinion when a range rather than a point estimate is concluded. Used alongside value_range_low for sensitivity analysis and investment committee reporting.',
    `value_range_low` DECIMAL(18,2) COMMENT 'The lower bound of the appraisers value range opinion when a range rather than a point estimate is concluded. Used in portfolio stress testing and sensitivity analysis in Argus Enterprise.',
    `value_type` STRING COMMENT 'The standard of value concluded in the appraisal report. Market Value is the most common; Investment Value reflects a specific investors criteria; Liquidation Value assumes a forced sale; Insurable Value is used for insurance replacement cost; Assessed Value is used for property tax purposes.. Valid values are `market|investment|liquidation|insurable|assessed`',
    CONSTRAINT pk_appraisal PRIMARY KEY(`appraisal_id`)
) COMMENT 'Master record for a formal property appraisal engagement, its deliverable report(s), and status lifecycle. Captures the appraisal order, assigned certified appraiser (MAI, SRA, AI-GRS), appraisal type (full, limited, desktop, drive-by), purpose (financing, disposition, insurance, tax appeal, portfolio review, litigation), USPAP/IVSC-compliant methodology, engagement and report delivery dates, status lifecycle (ordered → in-progress → review → completed/rejected), concluded market value, value date, report format (URAR, narrative, restricted, summary), value type (market, investment, liquidation, insurable), report version (as-is, as-stabilized, as-complete), engagement letter reference, fee, turnaround SLA, and Argus Enterprise model ID where applicable. SSOT for all formal appraisal engagements and their output reports across the portfolio.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`appraisal_report` (
    `appraisal_report_id` BIGINT COMMENT 'Unique surrogate identifier for the appraisal report record in the Silver Layer lakehouse. Primary key for this entity.',
    `appraisal_id` BIGINT COMMENT 'Reference to the parent appraisal engagement that commissioned this report. One engagement may produce multiple reports (e.g., as-is vs. as-stabilized).',
    `approach_id` BIGINT COMMENT 'Foreign key linking to valuation.approach. Business justification: An appraisal report is the formal deliverable that summarizes the valuation approaches applied. Linking appraisal_report.approach_id to approach.approach_id allows the report to reference the specific',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: Appraisal reports express gross_building_area_sqf and value_psf; the area UOM reference ensures consistent measurement standards (BOMA, IPMS, RICS) across cross-border portfolios. Institutional invest',
    `assessment_id` BIGINT COMMENT 'Foreign key linking to compliance.assessment. Business justification: Appraisal reports undergo compliance assessments for USPAP format compliance, lender QC review, and regulatory audit. Report-level assessments check scope of work, limiting conditions, and certificati',
    `asset_id` BIGINT COMMENT 'Reference to the subject property being appraised, linking to the property master record.',
    `brokerage_deal_id` BIGINT COMMENT 'Foreign key linking to brokerage.deal. Business justification: Appraisal reports are delivered as formal due diligence documents for specific deals. Lenders require the report tied to the deal for loan approval. Deal closing checklists track report delivery and a',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: Appraisal reports classify building class (A/B/C) which directly affects concluded value, comparable selection criteria, and cap rate applied. Lenders and CMBS underwriters require building class in a',
    `buyer_representation_id` BIGINT COMMENT 'Foreign key linking to brokerage.buyer_representation. Business justification: Appraisal reports are commissioned by buyer representation brokers for client due diligence. Linking the report to the buyer representation agreement enables tracking of appraisal contingency fulfillm',
    `capex_project_id` BIGINT COMMENT 'Foreign key linking to maintenance.capex_project. Business justification: Appraisal reports document as_stabilized_value and as_is_value scenarios driven by specific capital improvement projects. Lenders and investors require the report to cite the capex_project supporting ',
    `construction_type_id` BIGINT COMMENT 'Foreign key linking to reference.construction_type. Business justification: Appraisal reports document construction type as part of the property description section and cost approach analysis. Insurance underwriters and lenders require construction type in appraisal reports f',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Appraisal report costs are allocated to cost centers for internal chargeback and budget tracking. The cost center identifies the business unit that commissioned the report, a standard real estate acco',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Appraisal report monetary values (concluded_market_value, as_is_value, as_stabilized_value) require a normalized currency reference for multi-currency fund reporting and IFRS/GAAP fair value disclosur',
    `dcf_model_id` BIGINT COMMENT 'Foreign key linking to valuation.dcf_model. Business justification: An appraisal report may be supported by a specific DCF model (Argus Enterprise model). Linking appraisal_report.dcf_model_id to dcf_model.dcf_model_id enables direct traceability from the formal repor',
    `debt_instrument_id` BIGINT COMMENT 'Foreign key linking to finance.debt_instrument. Business justification: Appraisal reports are frequently ordered by lenders as a condition of loan origination or refinancing. The report must be tied to the specific debt instrument it supports for loan file documentation a',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: Appraisal reports are submitted as part of construction loan draw packages and lender compliance requirements. Linking appraisal_report directly to dev_project allows lenders to retrieve all reports f',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: Appraisal reports document market conditions, submarket trends, and comparable adequacy — all geographically defined. Linking to geographic_hierarchy enables submarket-level report analytics, market c',
    `industry_classification_id` BIGINT COMMENT 'Foreign key linking to reference.industry_classification. Business justification: Appraisal reports for commercial properties classify the primary tenant industry for income approach market rent benchmarking and re-leasing risk assessment. Institutional lenders require tenant indus',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction. Business justification: Appraisal reports are prepared under jurisdiction-specific regulatory standards (state licensing boards, USPAP enforcement). Reports filed for lending, litigation, or tax purposes must reference the g',
    `lease_type_id` BIGINT COMMENT 'Foreign key linking to reference.lease_type. Business justification: Appraisal reports document the predominant lease type (NNN, gross, modified gross) for income approach NOI calculation and expense recovery analysis. CMBS lenders and REIT auditors require lease type ',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Appraisal reports are relied upon by specific legal entities for ASC 820 / IFRS 13 fair value disclosures and SEC reporting. `client_name` is a denormalized text field; a proper FK to legal_entity ena',
    `listing_id` BIGINT COMMENT 'Foreign key linking to brokerage.listing. Business justification: Appraisal reports are delivered to support specific active listings — for seller pricing validation, buyer lender requirements, or MLS disclosure. Listing managers need to retrieve all appraisal repor',
    `market_research_id` BIGINT COMMENT 'Foreign key linking to marketing.market_research. Business justification: Appraisal reports reference market research studies in the market analysis section to document supply/demand conditions, absorption trends, and competitive set. USPAP requires identification of all da',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to reference.market_segment. Business justification: Appraisal reports are prepared for specific investment market segments (core, value-add, opportunistic) which determines the intended investor audience, discount rate assumptions, and IVSC methodology',
    `market_survey_id` BIGINT COMMENT 'Foreign key linking to marketing.market_survey. Business justification: Appraisal reports cite market surveys as supporting data for rent and vacancy assumptions used in the concluded value. The scope_of_work section of an appraisal report must identify all data sources —',
    `noi_statement_id` BIGINT COMMENT 'Foreign key linking to finance.noi_statement. Business justification: Appraisal reports document the NOI statement used as the income basis for the income approach. The report must reference the specific NOI statement underpinning the concluded value. noi_applied is a d',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: Appraisal reports document property-type-specific valuation approaches, comparable adequacy standards, and market conditions. The plain property_use_type column is a denormalized property type referen',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Appraisal reports are produced to satisfy specific regulatory obligations (FIRREA for federally regulated lenders, SEC fair value reporting, USPAP). Compliance teams trace which regulatory obligation ',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: Appraisal reports classify the subject propertys space use type to drive income approach assumptions and comparable selection. Space use type is a primary segmentation dimension in NCREIF and MSCI va',
    `transaction_type_id` BIGINT COMMENT 'Foreign key linking to reference.transaction_type. Business justification: Appraisal reports are commissioned for specific transaction types (acquisition, disposition, refinance, estate) which determines the intended use, standard of value, and required certifications. USPAP',
    `zoning_code_id` BIGINT COMMENT 'Foreign key linking to reference.zoning_code. Business justification: Appraisal reports must document the subject propertys zoning classification as part of the legal description and highest-and-best-use analysis — a mandatory USPAP requirement. Zoning conformity direc',
    `argus_model_reference` STRING COMMENT 'The file name, version identifier, or document reference for the Argus Enterprise cash flow model used to support the DCF valuation in this report. Enables traceability back to the source financial model.',
    `as_is_value` DECIMAL(18,2) COMMENT 'The appraised value of the property in its current physical and economic condition as of the effective date, without consideration of any proposed improvements or stabilization. Commonly used alongside as-stabilized value for development and repositioning assets.',
    `as_stabilized_value` DECIMAL(18,2) COMMENT 'The prospective appraised value of the property upon reaching stabilized occupancy and income levels, assuming completion of any proposed improvements. Used in development financing and investment underwriting.',
    `cap_rate_applied` DECIMAL(18,2) COMMENT 'The overall capitalization rate (CAP rate) applied in the income capitalization approach, expressed as a decimal (e.g., 0.0650 for 6.50%). Derived from comparable sales analysis and market data. Key input for NOI-based valuation.',
    `concluded_market_value` DECIMAL(18,2) COMMENT 'The appraisers final concluded value opinion for the subject property as of the effective date, expressed in the report currency. This is the primary quantitative output of the appraisal engagement and is used for investment decisions, financial reporting, and loan underwriting.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this appraisal report record was first created in the Silver Layer data platform. Supports audit trail and data lineage tracking.',
    `discount_rate` DECIMAL(18,2) COMMENT 'The discount rate applied in the Discounted Cash Flow (DCF) analysis, expressed as a decimal (e.g., 0.0800 for 8.00%). Reflects the required rate of return for the investment, incorporating risk and market conditions.',
    `effective_date` DATE COMMENT 'The date as of which the concluded value opinion is valid (also known as the value date). This is the principal real-world event date for the appraisal and may differ from the report date. Critical for investment decision-making and financial reporting under ASC 842 and IFRS 16.',
    `extraordinary_assumptions` STRING COMMENT 'Narrative description of any extraordinary assumptions made in the appraisal that, if found to be false, could alter the appraisers opinions or conclusions. Required USPAP disclosure. Examples include assumed lease-up timelines or assumed environmental clearance.',
    `gross_building_area_sqf` DECIMAL(18,2) COMMENT 'The total gross building area of the subject property in square feet (SQF) as measured or verified by the appraiser. Used to calculate per-square-foot (PSF) value indicators and compare to market comparables.',
    `holding_period_years` STRING COMMENT 'The assumed investment holding period in years used in the Discounted Cash Flow (DCF) analysis. Typically ranges from 5 to 15 years for commercial real estate. Drives the terminal value calculation.',
    `hypothetical_conditions` STRING COMMENT 'Narrative description of any hypothetical conditions applied in the appraisal that are contrary to known facts but assumed for the purpose of analysis (e.g., assuming a proposed building is complete as of the effective date). Required USPAP disclosure.',
    `inspection_date` DATE COMMENT 'The date on which the appraiser physically inspected the subject property. A desktop or drive-by appraisal may have no inspection date. Required for USPAP compliance certification.',
    `intended_use` STRING COMMENT 'The stated purpose for which the appraisal report is intended to be used, as required by USPAP (e.g., mortgage financing, financial reporting, portfolio valuation, acquisition due diligence, estate planning, litigation support). Determines the scope of work and applicable standards.',
    `intended_user` STRING COMMENT 'The party or parties identified by the appraiser as the intended user(s) of the appraisal report (e.g., lender name, client organization, REIT investment committee). Required USPAP disclosure. Restricts reliance on the report to named parties.',
    `irr` DECIMAL(18,2) COMMENT 'The Internal Rate of Return (IRR) output from the DCF analysis, expressed as a decimal. Represents the annualized rate of return that equates the present value of projected cash flows to the concluded value. Key metric for investment decision-making.',
    `limiting_conditions` STRING COMMENT 'Summary of the general and specific limiting conditions that govern the scope and reliance of the appraisal report. Standard USPAP certification element included in all appraisal reports.',
    `npv` DECIMAL(18,2) COMMENT 'The Net Present Value (NPV) output from the DCF analysis, representing the present value of projected future cash flows discounted at the applied discount rate. Supports investment advisory and portfolio management decisions.',
    `number_of_comparables` STRING COMMENT 'The count of comparable sales transactions analyzed and used in the sales comparison approach. Provides a quality indicator for the depth of market evidence supporting the concluded value.',
    `report_date` DATE COMMENT 'The date on which the appraisal report was signed and issued by the appraiser. May differ from the effective date of value, particularly for retrospective or prospective appraisals.',
    `report_format` STRING COMMENT 'The format type of the appraisal report as defined by USPAP and Fannie Mae guidelines. URAR (Uniform Residential Appraisal Report) is standard for residential; narrative and summary formats are common for commercial CRE engagements.. Valid values are `URAR|narrative|restricted|summary|desktop`',
    `report_number` STRING COMMENT 'Externally-known unique alphanumeric identifier assigned to the report by the appraisal firm or internal valuation team. Used for cross-referencing with Argus Enterprise and client deliverables.. Valid values are `^RPT-[0-9]{4}-[0-9]{6}$`',
    `report_scenario` STRING COMMENT 'The valuation scenario represented by this report. As-Is reflects current condition; As-Stabilized assumes full occupancy; As-Complete assumes construction completion; As-Dark assumes vacant/non-operating; Prospective reflects a future date. One engagement may produce multiple scenario reports.. Valid values are `as_is|as_stabilized|as_complete|as_dark|prospective`',
    `report_status` STRING COMMENT 'Current lifecycle state of the appraisal report workflow. Tracks progression from initial draft through internal review, approval, client issuance, and potential supersession or withdrawal.. Valid values are `draft|in_review|approved|issued|superseded|withdrawn`',
    `review_status` STRING COMMENT 'The current status of the internal or external review process for this appraisal report. Tracks whether a supervisory or desk review has been initiated, completed, approved, or rejected per Appraisal Institute and USPAP Standards Rule 3.. Valid values are `not_required|pending|in_progress|approved|rejected`',
    `reviewer_sign_off_date` DATE COMMENT 'The date on which the designated reviewer completed and approved the review of this appraisal report. Null if review is not yet completed or not required.',
    `scope_of_work` STRING COMMENT 'Description of the type and extent of research and analyses applied in the appraisal assignment, as required by USPAP Scope of Work Rule. Includes data sources consulted, inspection type, and approaches to value considered.',
    `terminal_cap_rate` DECIMAL(18,2) COMMENT 'The reversion or terminal CAP rate applied to the projected NOI at the end of the DCF holding period to estimate the terminal/residual value of the property. Used in Argus Enterprise DCF models.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this appraisal report record was last modified in the Silver Layer data platform. Supports change tracking, audit compliance, and data freshness monitoring.',
    `uspap_compliant` BOOLEAN COMMENT 'Indicates whether the report was prepared in compliance with USPAP (Uniform Standards of Professional Appraisal Practice) as required by the Appraisal Institute and applicable US regulations.',
    `valuation_approach` STRING COMMENT 'Primary valuation methodology applied in the report. Sales Comparison uses comparable transactions; Income Capitalization applies CAP rate to NOI; Cost approach estimates replacement cost less depreciation; DCF (Discounted Cash Flow) models future cash flows; Hybrid combines multiple approaches.. Valid values are `sales_comparison|income_capitalization|cost|dcf|hybrid`',
    `value_psf` DECIMAL(18,2) COMMENT 'The concluded market value expressed on a per-square-foot (PSF) basis, calculated as concluded market value divided by gross building area. Key benchmarking metric for CRE investment analysis and market comparison.',
    `value_type` STRING COMMENT 'The basis of value concluded in the report. Market Value is the most common standard; Investment Value reflects a specific investors criteria; Liquidation Value applies to distressed scenarios; Insurable Value is used for insurance purposes; Assessed Value is used for tax purposes.. Valid values are `market_value|investment_value|liquidation_value|insurable_value|assessed_value`',
    CONSTRAINT pk_appraisal_report PRIMARY KEY(`appraisal_report_id`)
) COMMENT 'The formal deliverable output of an appraisal engagement. Stores report format (URAR, narrative, restricted, summary), concluded market value, value date (effective date of value), report date, value type (market value, investment value, liquidation value, insurable value), IVSC standard applied, report file reference (DocuSign CLM document ID), review status, and reviewer sign-off. One appraisal engagement may produce one or more reports (e.g., as-is vs. as-stabilized).';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`bpo` (
    `bpo_id` BIGINT COMMENT 'Unique system-generated identifier for the Broker Price Opinion record. Primary key for the bpo data product in the valuation domain.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: BPO values are expressed per square foot or square meter; the area UOM reference ensures consistent measurement standards across markets. Servicers aggregating BPO data across portfolios require UOM s',
    `asset_id` BIGINT COMMENT 'Reference to the subject property being valued in this BPO engagement.',
    `broker_id` BIGINT COMMENT 'Reference to the licensed real estate broker who prepared and signed the BPO.',
    `brokerage_deal_id` BIGINT COMMENT 'Foreign key linking to brokerage.brokerage_deal. Business justification: BPOs are ordered in the context of specific brokerage deals — short sales, REO dispositions, and distressed asset transactions require a BPO before deal approval. Linking BPO to the deal supports deal',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: BPO costs are budgeted line items in real estate operations. Linking BPO to finance_budget supports budget vs. actual tracking of valuation and due-diligence costs for lenders and servicers.',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: BPOs classify the subject propertys building class to select appropriate comparable sales and support the brokers opinion of value. Mortgage servicers and special servicers require building class in',
    `construction_type_id` BIGINT COMMENT 'Foreign key linking to reference.construction_type. Business justification: BPOs document construction type for property condition assessment and repair cost estimation (repair_cost_estimate field). Servicers and insurers require construction type in BPOs to validate insuranc',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: BPO fees are operational costs coded to cost centers. Lenders and servicers track BPO costs by cost center for expense management and budget variance analysis. No existing unlinked column; default PK ',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: BPO financial outputs (opinion_value, recommended_list_price, quick_sale_value, repair_cost_estimate) are currency-denominated. Normalizing to a FK supports multi-currency asset management reporting a',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: BPO market conditions narrative, comparable selection, and estimated DOM are submarket-specific. Linking to geographic_hierarchy enables submarket-level BPO analytics, broker panel management by geogr',
    `industry_classification_id` BIGINT COMMENT 'Foreign key linking to reference.industry_classification. Business justification: BPOs for commercial properties classify the primary tenant industry to benchmark market rents and assess re-leasing risk in the brokers opinion. Servicers require tenant industry classification for R',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction. Business justification: BPO regulatory status varies by jurisdiction — several states prohibit BPOs for mortgage origination. Compliance teams must track which jurisdiction governs each BPO to enforce broker licensing rules ',
    `listing_agreement_id` BIGINT COMMENT 'Foreign key linking to brokerage.listing_agreement. Business justification: BPOs are prepared by the listing broker as part of listing agreement execution to establish recommended list price. The listing agreement authorizes the broker to provide the BPO. This link supports l',
    `listing_id` BIGINT COMMENT 'Foreign key linking to brokerage.listing. Business justification: BPOs are ordered by listing brokers or asset managers to set or validate listing prices before or during active marketing. Linking BPO to listing enables direct traceability between the broker price o',
    `market_survey_id` BIGINT COMMENT 'Foreign key linking to marketing.market_survey. Business justification: BPO preparation requires current submarket rent, vacancy, and concession data from market surveys. Brokers completing BPOs reference the most recent market survey for the subject submarket to support ',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: BPO methodology, comparable selection, and market trend analysis differ fundamentally by property type (residential vs commercial vs industrial). A domain expert would expect every BPO to reference th',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: BPOs used in mortgage servicing (loss mitigation, REO disposition) must comply with specific regulatory obligations (CFPB servicing rules, GSE guidelines, state broker licensing requirements). Complia',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: BPOs for commercial properties require space use classification to identify relevant comparable sales and leases. Servicers and asset managers use space use type to route BPO orders to brokers with ap',
    `transaction_type_id` BIGINT COMMENT 'Foreign key linking to reference.transaction_type. Business justification: BPOs are ordered for specific transaction purposes (REO disposition, short sale, refinance, pre-listing). The transaction type determines the BPO scope, value basis (as-is vs quick-sale), and lender r',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: BPOs for residential REO and mortgage default servicing are ordered at the unit level (individual condo, townhome). The BPO captures unit-level condition, occupancy_status, and opinion_value. Mortgage',
    `zoning_code_id` BIGINT COMMENT 'Foreign key linking to reference.zoning_code. Business justification: BPOs document zoning classification for highest-and-best-use commentary and legal conformity analysis. Lenders and servicers require zoning documentation in BPOs to assess redevelopment potential and ',
    `as_repaired_value` DECIMAL(18,2) COMMENT 'The brokers estimated market value of the subject property assuming all identified repairs and deferred maintenance items have been completed. Used to assess post-rehabilitation value for REO and distressed asset management.',
    `basis_for_opinion` STRING COMMENT 'A narrative description of the primary methodological basis and evidence used by the broker to arrive at the opinion of value, including comparable sales, active listings, and market data sources.',
    `bpo_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to the BPO engagement, used for tracking and communication with requesting parties and lenders.. Valid values are `^BPO-[0-9]{4}-[0-9]{6}$`',
    `bpo_status` STRING COMMENT 'Current workflow state of the BPO engagement lifecycle, from initial order through completion, review, and potential expiry or cancellation.. Valid values are `ordered|in-progress|completed|reviewed|cancelled|expired`',
    `bpo_type` STRING COMMENT 'Classification of the BPO inspection methodology: drive-by (exterior-only observation), interior (full interior and exterior inspection), or desktop (no physical inspection; relies on MLS and public data).. Valid values are `drive-by|interior|desktop`',
    `broker_company_name` STRING COMMENT 'The name of the brokerage firm or company under which the preparing broker operates, as it appears on the BPO report.',
    `broker_license_number` STRING COMMENT 'The state-issued real estate broker license number of the individual who prepared and certified the BPO. Required for regulatory compliance and to validate the brokers authority to provide a price opinion.',
    `broker_license_state` STRING COMMENT 'The U.S. state (two-letter USPS abbreviation) in which the brokers license is issued and under which the BPO is prepared.. Valid values are `^[A-Z]{2}$`',
    `completed_date` DATE COMMENT 'The date on which the broker submitted the completed BPO report to the requesting party.',
    `costar_property_reference` STRING COMMENT 'The CoStar Suite property identifier for the subject property, enabling cross-reference to CoStar market research, comparable sales, and property analytics data.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the BPO record was first created in the system, used for audit trail and data lineage tracking.',
    `effective_date` DATE COMMENT 'The as-of date for which the brokers opinion of value is valid. Market conditions and comparable evidence are assessed relative to this date.',
    `engagement_fee` DECIMAL(18,2) COMMENT 'The fee charged by the broker for completing the BPO engagement, as agreed with the requesting party. Used for accounts payable processing and vendor cost tracking.',
    `estimated_dom` STRING COMMENT 'The brokers estimate of the number of days the subject property would remain on the market before a sale at the recommended list price under current market conditions.',
    `expiry_date` DATE COMMENT 'The date after which the BPO opinion of value is considered stale and no longer reliable for decision-making, typically 90–180 days from the effective date.',
    `inspection_date` DATE COMMENT 'The date on which the broker physically inspected the subject property (applicable for drive-by and interior BPO types). Null for desktop BPOs.',
    `intended_use` STRING COMMENT 'The stated purpose for which the BPO is being prepared, such as REO pricing, loss mitigation, pre-listing assessment, or portfolio valuation. Governs scope and reliance limitations. [ENUM-REF-CANDIDATE: loss-mitigation|reo-pricing|pre-listing|portfolio-valuation|loan-origination|other — promote to reference product]. Valid values are `loss-mitigation|reo-pricing|pre-listing|portfolio-valuation|loan-origination|other`',
    `is_rush_order` BOOLEAN COMMENT 'Indicates whether the BPO was ordered on an expedited or rush basis, typically associated with a higher engagement fee and shorter turnaround SLA.',
    `market_conditions_narrative` STRING COMMENT 'The brokers qualitative description of current local market conditions, including supply/demand dynamics, absorption rates, price trends, and competitive environment influencing the subject propertys value.',
    `market_trend` STRING COMMENT 'The brokers assessment of the directional trend in property values in the subject market area at the time of the BPO effective date.. Valid values are `increasing|stable|declining`',
    `mls_number` STRING COMMENT 'The MLS listing number of the subject property if it is currently or was recently listed on the MLS, used to cross-reference active listing data in CoStar or local MLS systems.',
    `num_comparable_listings` STRING COMMENT 'The count of active or pending comparable listings used as competitive market evidence in the BPO.',
    `num_comparable_sales` STRING COMMENT 'The count of closed comparable sales transactions used as evidence in the BPOs sales comparison approach.',
    `occupancy_status` STRING COMMENT 'The occupancy status of the subject property at the time of the BPO inspection, which affects marketability, condition assessment, and value conclusions.. Valid values are `owner-occupied|tenant-occupied|vacant|unknown`',
    `opinion_value` DECIMAL(18,2) COMMENT 'The brokers point-estimate opinion of the subject propertys market value as of the effective date, expressed in the local currency (USD). This is the primary valuation output of the BPO.',
    `ordered_date` DATE COMMENT 'The date on which the BPO was formally ordered or requested by the requesting party.',
    `property_condition` STRING COMMENT 'The brokers assessment of the overall physical condition of the subject property at the time of inspection, used as a key input to value adjustments.. Valid values are `excellent|good|average|fair|poor`',
    `quick_sale_value` DECIMAL(18,2) COMMENT 'The estimated value achievable in an accelerated or distressed sale scenario (e.g., REO liquidation), typically below the as-is market value. Used by lenders for loss mitigation analysis.',
    `recommended_list_price` DECIMAL(18,2) COMMENT 'The brokers recommended listing price for the subject property if placed on the open market, which may differ from the opinion of value based on current market absorption and competitive positioning.',
    `repair_cost_estimate` DECIMAL(18,2) COMMENT 'The brokers estimate of the total cost of repairs and deferred maintenance items identified during the inspection, used to bridge the as-is value to the as-repaired value.',
    `report_document_url` STRING COMMENT 'The URL or file path to the completed BPO report document stored in the document management system (e.g., DocuSign CLM or enterprise document repository).',
    `requester_reference` STRING COMMENT 'The requesting partys own internal reference or order number for this BPO engagement, used for cross-referencing and reconciliation with the clients systems.',
    `review_status` STRING COMMENT 'The quality review status of the completed BPO, indicating whether it has been approved by the requesting partys review team, rejected, or requires revision.. Valid values are `pending-review|approved|rejected|revision-required`',
    `reviewer_notes` STRING COMMENT 'Qualitative notes or feedback provided by the reviewing party upon quality review of the BPO, including reasons for rejection or required revisions.',
    `turnaround_sla_hours` STRING COMMENT 'The contractually agreed turnaround time in hours from order placement to BPO delivery, as specified in the engagement agreement with the requesting party.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when the BPO record was last modified in the system, supporting audit trail, change tracking, and incremental data pipeline processing.',
    `value_range_high` DECIMAL(18,2) COMMENT 'The upper bound of the brokers estimated value range for the subject property, reflecting upside market conditions or superior comparable evidence.',
    `value_range_low` DECIMAL(18,2) COMMENT 'The lower bound of the brokers estimated value range for the subject property, reflecting downside market conditions or property condition adjustments.',
    CONSTRAINT pk_bpo PRIMARY KEY(`bpo_id`)
) COMMENT 'Broker Price Opinion record capturing informal property value estimates prepared by licensed real estate brokers. Stores BPO type (drive-by, interior, desktop), requesting party, intended use, broker license number, opinion of value (point estimate and low/high range), effective date, market conditions narrative, days-on-market estimate, recommended list price, basis for opinion, engagement fee, turnaround SLA, requester reference, and comparable evidence references. Used for quick portfolio valuations, REO pricing, pre-listing assessments, and lender loss mitigation where a full USPAP appraisal is not required.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`cma` (
    `cma_id` BIGINT COMMENT 'Unique system-generated identifier for the Comparative Market Analysis record. Primary key for the cma data product in the valuation domain.',
    `address_id` BIGINT COMMENT 'Foreign key linking to property.address. Business justification: CMA has subject_address, subject_city, subject_state, subject_zip as plain text — clear denormalization of property.address. Normalizing via FK to property.address enforces 3NF, enables geocoding/mapp',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: CMAs express avg_comparable_psf and recommended_list_price per area unit; the UOM reference ensures consistent measurement standards. MLS systems require UOM standardization for price-per-area compari',
    `asset_id` BIGINT COMMENT 'Reference to the subject property being analyzed in this CMA. Links to the property master record in the property domain.',
    `broker_id` BIGINT COMMENT 'Foreign key linking to brokerage.brokerage_broker. Business justification: CMAs are prepared by a specific licensed broker and attributed to that broker for production tracking, license compliance, and client advisory records. Broker production reports require knowing which ',
    `brokerage_deal_id` BIGINT COMMENT 'Foreign key linking to brokerage.brokerage_deal. Business justification: CMAs are produced to support active deal negotiations — brokers prepare CMAs to justify offer prices or counter-offers during deal progression. Linking CMA to the deal enables deal pipeline analytics ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: CMA preparation costs are allocated to cost centers in property management and brokerage operations. CMAs ordered for listing decisions must be coded to the responsible cost center for expense trackin',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: CMA financial outputs (concluded_value_low/high, recommended_list_price, avg_comparable_psf) are currency-denominated. Normalizing the plain currency_code column to a FK enables consistent currency ha',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: CMAs are prepared for residential development projects to establish pre-sale pricing strategy and market absorption analysis. Linking cma to dev_project allows the development team to track market pri',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: CMA comparable selection, absorption rate, months of supply, and market trend data are submarket-specific. Linking to geographic_hierarchy enables submarket-level CMA analytics, MLS area mapping, and ',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction. Business justification: CMAs are prepared for properties in specific jurisdictions whose disclosure rules, licensing requirements, and market data standards govern the analysis. Compliance officers and appraisers need jurisd',
    `listing_agreement_id` BIGINT COMMENT 'Foreign key linking to brokerage.listing_agreement. Business justification: CMAs are the primary pricing tool prepared under a listing agreement to set the recommended list price. The listing agreement mandates the broker provide a CMA to the seller. This link supports listin',
    `listing_id` BIGINT COMMENT 'Foreign key linking to brokerage.listing. Business justification: CMAs are the primary tool brokers use to set recommended list prices for a specific listing. A CMA is almost always produced in direct support of a listing engagement. Linking CMA to listing enables l',
    `market_research_id` BIGINT COMMENT 'Foreign key linking to marketing.market_research. Business justification: CMAs use market research for demand/supply trend analysis, absorption rates, and competitive set context. The cma.market_condition and market_trend fields are populated from market research findings —',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to reference.market_segment. Business justification: CMAs are prepared for specific market segments (luxury, affordable, mid-market) which determines the comparable pool and pricing strategy. Brokerage firms segment CMA production by market tier for age',
    `market_survey_id` BIGINT COMMENT 'Foreign key linking to marketing.market_survey. Business justification: CMAs are directly informed by market survey data — avg asking rent PSF, vacancy rates, months of supply, and concessions. A real estate analyst preparing a CMA pulls the current market survey for the ',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: CMAs are property-type specific (SFR, condo, multifamily, commercial) which determines comparable selection criteria and pricing methodology. The cma product has a plain property_type column that shou',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: CMAs prepared for lending, litigation, or investment decisions are subject to regulatory obligations (USPAP, state licensing statutes). Tracking the governing obligation enables compliance audits of C',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Commercial lease advisory CMAs are performed for specific leasable spaces to determine market rent for a suite. CMA links to asset and unit but not space. Space-level CMAs are standard in tenant rep a',
    `transaction_type_id` BIGINT COMMENT 'Foreign key linking to reference.transaction_type. Business justification: CMAs are prepared for specific transaction types (listing for sale, refinance, estate, divorce) which determines the pricing strategy and comparable selection criteria. Brokers and agents always speci',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: CMAs are conducted for specific residential units (condos, apartments) to support listing price decisions. cma has subject_sqft, subject_bedrooms, subject_bathrooms, subject_year_built — all denormali',
    `absorption_rate` DECIMAL(18,2) COMMENT 'The rate at which available properties in the subject market are sold over a given period, expressed as a percentage or number of homes sold per month. A key indicator of market velocity and pricing power.',
    `active_comparable_count` STRING COMMENT 'Number of currently active listing comparables included in the analysis. Active listings represent current competition and establish the upper bound of buyer expectations.',
    `analysis_date` DATE COMMENT 'The date on which the Comparative Market Analysis was conducted and the market data was assembled. This is the effective date of the analysis, not the delivery date.',
    `analyst_notes` STRING COMMENT 'Free-text narrative commentary from the broker or agent explaining the comparable selection rationale, market observations, adjustments made, and any qualifications on the concluded value range.',
    `avg_comparable_psf` DECIMAL(18,2) COMMENT 'The average sale price per square foot (PSF) across all comparable sales used in the analysis. Key metric for value benchmarking and pricing strategy validation.',
    `avg_days_on_market` STRING COMMENT 'Average number of days comparable sold properties were listed on the market before going under contract. Informs realistic time-to-sale expectations for the seller.',
    `cma_number` STRING COMMENT 'Externally-visible business identifier for the CMA engagement, used in client-facing reports and broker correspondence. Format: CMA-{YYYY}-{NNNNNN}.. Valid values are `^CMA-[0-9]{4}-[0-9]{6}$`',
    `cma_status` STRING COMMENT 'Current lifecycle state of the CMA record. Draft indicates work-in-progress; delivered indicates client receipt; superseded indicates a newer CMA has replaced this one for the same property.. Valid values are `draft|in_review|delivered|superseded|expired|cancelled`',
    `comparable_count` STRING COMMENT 'Total number of comparable properties (sold, active, and pending listings) used in the analysis. A higher count generally increases the reliability of the concluded value range.',
    `comparable_lookback_months` STRING COMMENT 'The number of months of historical sales data reviewed when selecting comparable sold properties. Typically 3–12 months depending on market activity and data availability.',
    `comparable_search_radius_miles` DECIMAL(18,2) COMMENT 'The geographic radius in miles used to define the comparable property search area around the subject property. Smaller radii indicate tighter, more homogeneous market areas.',
    `concluded_value_high` DECIMAL(18,2) COMMENT 'The upper bound of the analysts concluded market value range for the subject property, expressed in USD. Together with concluded_value_low, defines the recommended pricing corridor.',
    `concluded_value_low` DECIMAL(18,2) COMMENT 'The lower bound of the analysts concluded market value range for the subject property, expressed in USD. Together with concluded_value_high, defines the recommended pricing corridor for seller consultations.',
    `costar_report_reference` STRING COMMENT 'Reference identifier for the CoStar Suite market report or comparable data export used as a data source for this CMA. Supports data lineage and source traceability.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this CMA record was first created in the system. Audit trail field supporting data governance and SOX compliance for financial reporting inputs.',
    `delivery_date` DATE COMMENT 'The date the completed CMA report was delivered to the client or seller. May differ from analysis_date if preparation spans multiple days.',
    `engagement_type` STRING COMMENT 'The business purpose or context for which this CMA was prepared. Drives the analytical focus and recommended pricing strategy. [ENUM-REF-CANDIDATE: listing_price_recommendation|seller_consultation|buyer_advisory|refinance_support|estate_settlement|other — promote to reference product]. Valid values are `listing_price_recommendation|seller_consultation|buyer_advisory|refinance_support|estate_settlement|other`',
    `expiry_date` DATE COMMENT 'The date after which the CMA conclusions are considered stale and should not be relied upon for pricing decisions, typically 90–180 days from analysis date given market volatility.',
    `is_uspap_compliant` BOOLEAN COMMENT 'Indicates whether this CMA was prepared in accordance with USPAP standards. CMAs are typically NOT USPAP-compliant (False) as they are broker-prepared market analyses, not certified appraisals. This flag distinguishes CMAs from formal appraisals for regulatory and disclosure purposes.',
    `list_to_sale_ratio` DECIMAL(18,2) COMMENT 'The average ratio of final sale price to original list price across comparable sold properties, expressed as a decimal (e.g., 0.97 = 97%). Indicates negotiation dynamics and pricing accuracy in the local market.',
    `market_condition` STRING COMMENT 'Classification of the current supply-demand balance in the subject propertys local market. Sellers markets have low inventory and high demand; buyers markets have high inventory and low demand.. Valid values are `sellers_market|balanced_market|buyers_market`',
    `market_trend` STRING COMMENT 'Analysts assessment of the current directional trend in the subject propertys local market. Influences pricing strategy recommendations — appreciating markets may support aggressive pricing; declining markets warrant conservative pricing.. Valid values are `appreciating|stable|declining`',
    `mls_area_code` STRING COMMENT 'The MLS-defined geographic area or submarket code within which the subject property and comparables are located. Ensures comparables are drawn from the same MLS market area.',
    `months_of_supply` DECIMAL(18,2) COMMENT 'Estimated number of months it would take to sell all current active listings at the current absorption rate. Less than 3 months indicates a sellers market; more than 6 months indicates a buyers market.',
    `pending_comparable_count` STRING COMMENT 'Number of pending (under contract) comparable listings included in the analysis. Pending comparables indicate near-term market clearing prices.',
    `pricing_strategy` STRING COMMENT 'The analysts recommended pricing approach for the listing based on market conditions, seller objectives, and CMA findings. Aggressive pricing targets above-market value; below-market pricing aims for rapid sale.. Valid values are `aggressive|market_value|conservative|below_market`',
    `recommended_list_price` DECIMAL(18,2) COMMENT 'The specific listing price recommended by the analyst based on the CMA findings, market trend assessment, and pricing strategy. Falls within or near the concluded value range.',
    `report_document_url` STRING COMMENT 'URL or file path to the generated CMA report document (PDF or presentation format) stored in the document management system or DocuSign CLM. Supports client delivery and audit trail.',
    `sold_comparable_count` STRING COMMENT 'Number of recently sold comparable properties included in the analysis. Sold comparables are the primary evidence of market value in a CMA.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this CMA record was most recently modified. Supports change tracking, data lineage, and audit compliance in the Databricks Silver Layer.',
    CONSTRAINT pk_cma PRIMARY KEY(`cma_id`)
) COMMENT 'Comparative Market Analysis record used by brokers and agents to estimate property value based on recent comparable sales and active listings. Stores subject property reference, analysis date, analyst (broker/agent), concluded value range, number of comparables used, market trend assessment (appreciating, stable, declining), absorption rate, average PSF of comparables, recommended pricing strategy, and engagement context. Distinct from BPO (less formal, agent-prepared, not broker-licensed requirement) and from full appraisal (not USPAP-compliant). Self-contained engagement record used primarily for listing price recommendations and seller consultations.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`comparable_sale` (
    `comparable_sale_id` BIGINT COMMENT 'Primary key for comparable_sale',
    `appraisal_id` BIGINT COMMENT 'Reference to the parent appraisal, BPO, or CMA engagement for which this comparable sale record was selected and analyzed.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: Comparable sale price_psf and price_psm calculations require a defined area measurement unit (SF, SM, acres). Cross-market comparable analysis requires UOM normalization; linking to uom enables area-u',
    `asset_id` BIGINT COMMENT 'Reference to the subject property record in the property master data, linking the comparable sale to the property being appraised or valued.',
    `bpo_id` BIGINT COMMENT 'Foreign key linking to valuation.bpo. Business justification: BPOs (Broker Price Opinions) use comparable sales as evidence for the opinion of value. comparable_sale already has appraisal_id for appraisal-linked comps. Adding bpo_id (nullable) allows comparable ',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: Comparable sales are filtered and adjusted by building class (A/B/C) in the sales comparison approach — a primary selection criterion in USPAP-compliant appraisals. Appraisers must document building c',
    `cma_id` BIGINT COMMENT 'Foreign key linking to valuation.cma. Business justification: CMAs (Comparative Market Analyses) are built on comparable sales data. comparable_sale already has appraisal_id for appraisal-linked comps. Adding cma_id (nullable) allows comparable sales to be linke',
    `construction_type_id` BIGINT COMMENT 'Foreign key linking to reference.construction_type. Business justification: Comparable sales document construction type for physical adjustment calculations in the sales comparison approach. Appraisers must justify physical_adjustment_pct based on construction quality differe',
    `country_id` BIGINT COMMENT 'Foreign key linking to reference.country. Business justification: Comparable sales in international portfolios require country context for legal system, measurement standard, and currency normalization. The plain country_code column is denormalized; normalizing to a',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Comparable sale prices (sale_price, adjusted_sale_price, price_psf) are currency-denominated. Normalizing to a FK is essential for cross-border comparable analysis and currency-adjusted appraisal adju',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: Comparable sales require submarket-level geographic hierarchy for market analysis and location adjustment calculations. Appraisers filter comparable sales by submarket to ensure geographic comparabili',
    `approach_id` BIGINT COMMENT 'Foreign key linking to valuation.valuation_approach. Business justification: The sales comparison approach (valuation_approach with approach_type = SALES_COMPARISON) relies on comparable sales as primary evidence. Adding income_approach_id (nullable, using the PK of valuatio',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction. Business justification: Comparable sales are jurisdiction-specific: transfer tax rules, disclosure requirements, and data availability vary by jurisdiction. Appraisers filter comps by jurisdiction for regulatory compliance. ',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to property.parcel. Business justification: Land and development site appraisals use parcel-level comparable sales. When the comparable is an in-portfolio parcel, linking comparable_sale to property.parcel enables direct land value benchmarking',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: Comparable sales are filtered and adjusted by property type; the property_type plain column is a denormalized reference. Normalizing to a FK enables property-type-specific comparable databases, adjust',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: Comparable sales are classified by space use type to ensure apples-to-apples comparison in the sales comparison approach. Appraisers filter comparable sales by space use type as a primary selection cr',
    `transaction_type_id` BIGINT COMMENT 'Foreign key linking to reference.transaction_type. Business justification: Comparable sale transaction type (arms length, REO, short sale, portfolio trade) determines whether the sale is a valid market indicator and what adjustments are required. The plain sale_type column ',
    `zoning_code_id` BIGINT COMMENT 'Foreign key linking to reference.zoning_code. Business justification: Comparable sales document zoning for legal conformity analysis and adjustment in the sales comparison approach. Appraisers must verify that comparable properties have similar zoning to the subject to ',
    `address_line1` STRING COMMENT 'Primary street address of the comparable sale property (street number and street name). Used to identify the physical location of the comp for geographic adjustment analysis.',
    `address_line2` STRING COMMENT 'Secondary address information for the comparable sale property (suite, unit, floor, building name). Supplements the primary address for precise property identification.',
    `adjusted_price_psf` DECIMAL(18,2) COMMENT 'The adjusted sale price divided by the gross leasable area, expressed as adjusted price per square foot (PSF). The primary reconciled unit-of-comparison metric used to bracket and support the subject propertys value conclusion.',
    `adjusted_sale_price` DECIMAL(18,2) COMMENT 'The comparable sale price after application of all adjustments (location, physical, time, and other). This is the final adjusted value indicator used in the reconciliation of the sales comparison approach to derive the subject propertys market value opinion.',
    `appraiser_notes` STRING COMMENT 'Free-text narrative notes entered by the appraiser describing the rationale for selecting this comparable, the basis for adjustments applied, and any special circumstances affecting the sale. Required for USPAP Standard 1 documentation of the sales comparison approach.',
    `arms_length_flag` BOOLEAN COMMENT 'Indicates whether the comparable sale was an arms length transaction between unrelated parties with no undue influence (True) or a non-arms length transaction (False) such as a foreclosure, related-party sale, or distressed sale. Non-arms length transactions require additional adjustment or exclusion per USPAP.',
    `cap_rate_at_sale` DECIMAL(18,2) COMMENT 'The implied capitalization rate (CAP rate) at the time of the comparable sale, calculated as the net operating income (NOI) divided by the sale price. A key market indicator used in income approach cross-checks and investment analysis.',
    `comp_reference_number` STRING COMMENT 'Externally-known identifier for this comparable sale record, typically sourced from CoStar Suite, MLS, or public record systems (e.g., CoStar property ID, MLS listing number, or county assessor parcel number).',
    `condition_rating` STRING COMMENT 'Overall physical condition rating of the comparable sale property at the time of sale. Used to determine physical adjustment requirements in the sales comparison approach.. Valid values are `excellent|good|average|fair|poor`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this comparable sale record was first created in the system, supporting audit trail and data lineage requirements.',
    `data_source` STRING COMMENT 'Primary source from which the comparable sale data was obtained (e.g., CoStar Suite, MLS data feed, county deed/public record, appraiser files). Supports USPAP verification and data provenance requirements.. Valid values are `costar|mls|public_record|deed|appraiser_files|loopnet`',
    `data_source_record_reference` STRING COMMENT 'The unique identifier of this comparable sale record within the originating source system (e.g., CoStar property ID, MLS listing number, county assessor parcel number). Enables traceability back to the source system for verification.',
    `distressed_sale_flag` BOOLEAN COMMENT 'Indicates whether the comparable sale was a distressed transaction (True), such as a foreclosure, Real Estate Owned (REO) sale, short sale, or bankruptcy sale. Distressed sales may require exclusion or significant adjustment in USPAP-compliant appraisals.',
    `financing_type` STRING COMMENT 'Type of financing used in the comparable sale transaction (e.g., conventional mortgage, cash, seller financing, assumed mortgage, CMBS). Atypical financing may require a cash equivalency adjustment per USPAP.. Valid values are `conventional|cash|seller_financing|assumed|cmbs|other`',
    `gla_sqft` DECIMAL(18,2) COMMENT 'Total gross leasable area (GLA) of the comparable sale property measured in square feet (SQF). Primary size metric used to calculate price per square foot (PSF) and to assess comparability with the subject property.',
    `location_adjustment_pct` DECIMAL(18,2) COMMENT 'Percentage adjustment applied to the comparable sale price to account for locational differences between the comparable property and the subject property (e.g., submarket quality, access, visibility, corner location). Positive values indicate the subject is superior; negative values indicate the comparable is superior.',
    `lot_size_sqft` DECIMAL(18,2) COMMENT 'Total land area of the comparable sale property parcel measured in square feet. Critical for land valuation, FAR analysis, and comparability assessment for properties where land value is a significant component.',
    `nla_sqft` DECIMAL(18,2) COMMENT 'Net leasable area (NLA) of the comparable sale property measured in square feet, excluding common areas. Used as an alternative unit of comparison for properties where NLA is the market-standard measurement basis.',
    `noi_at_sale` DECIMAL(18,2) COMMENT 'The net operating income (NOI) of the comparable property at the time of sale, used to calculate the implied CAP rate and to support income approach cross-validation in the appraisal.',
    `number_of_stories` STRING COMMENT 'Total number of above-grade floors or stories in the comparable sale property. Used as a physical characteristic for comparability assessment and adjustment.',
    `occupancy_rate_pct` DECIMAL(18,2) COMMENT 'Percentage of the comparable property that was occupied at the time of sale. Used to assess income-producing capacity and to determine whether occupancy-related adjustments are required.',
    `parking_spaces` STRING COMMENT 'Total number of parking spaces (surface, structured, or underground) associated with the comparable sale property. Used to assess parking ratio and determine parking-related adjustments.',
    `physical_adjustment_pct` DECIMAL(18,2) COMMENT 'Percentage adjustment applied to the comparable sale price to account for physical differences between the comparable and subject property (e.g., size, age, condition, quality, amenities). Positive values indicate the subject is superior.',
    `postal_code` STRING COMMENT 'ZIP or postal code of the comparable sale property location. Used for submarket delineation, geographic clustering, and location adjustment analysis.',
    `price_psf` DECIMAL(18,2) COMMENT 'Sale price divided by the gross leasable area or building area, expressed as price per square foot (PSF). A primary unit-of-comparison metric used in the sales comparison approach for commercial and residential appraisals.',
    `price_psm` DECIMAL(18,2) COMMENT 'Sale price divided by the building area expressed in square meters (SQM). Used for international valuations and IVSC-compliant reporting where metric units are required.',
    `property_subtype` STRING COMMENT 'More granular classification of the comparable property within its property type (e.g., Class A Office, Strip Center, Bulk Warehouse, Garden Apartment). Supports refined comparability analysis.',
    `quality_rating` STRING COMMENT 'Rating of the construction quality and finish level of the comparable sale property. Used to assess quality-based adjustments in the sales comparison approach.. Valid values are `luxury|above_average|average|below_average|economy`',
    `sale_date` DATE COMMENT 'The date on which the comparable property sale was recorded or closed, used as the principal business event date for time adjustment calculations in the sales comparison approach.',
    `sale_price` DECIMAL(18,2) COMMENT 'The gross transaction price at which the comparable property sold, expressed in the local currency. This is the unadjusted arms-length sale price as recorded in deed or public record.',
    `time_adjustment_pct` DECIMAL(18,2) COMMENT 'Percentage adjustment applied to the comparable sale price to account for market conditions changes between the comparable sale date and the effective appraisal date. Reflects market appreciation or depreciation over the intervening period.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this comparable sale record was most recently modified, supporting audit trail, data lineage, and change tracking requirements.',
    `verification_date` DATE COMMENT 'The date on which the comparable sale data was verified against the primary source. Supports USPAP compliance documentation and audit trail requirements.',
    `verification_method` STRING COMMENT 'The method used to verify the accuracy of the comparable sale data (e.g., public deed record, direct buyer/seller confirmation, broker confirmation, CoStar verification). Required by USPAP Standard 1 for sales comparison approach documentation.. Valid values are `public_record|buyer_confirmation|seller_confirmation|broker_confirmation|costar|mls`',
    `verification_status` STRING COMMENT 'Current verification status of the comparable sale record indicating whether the sale data has been confirmed against primary sources (deed records, CoStar, MLS, or direct buyer/seller confirmation) per USPAP verification requirements.. Valid values are `verified|unverified|pending|rejected`',
    `year_built` STRING COMMENT 'The calendar year in which the comparable sale property was originally constructed. Used to assess age-related physical depreciation and comparability with the subject property.',
    CONSTRAINT pk_comparable_sale PRIMARY KEY(`comparable_sale_id`)
) COMMENT 'Individual comparable sale (comp) record used as evidence in appraisals, BPOs, and CMAs. Stores comp property address, sale date, sale price, price PSF, GLA/NLA, property type, year built, condition, location adjustments, physical adjustments, time adjustments, adjusted sale price, data source (CoStar, MLS, public record), and verification status. Supports the sales comparison approach in USPAP/IVSC-compliant valuations. Sourced from CoStar Suite and MLS data feeds.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`comparable_lease` (
    `comparable_lease_id` BIGINT COMMENT 'Unique system-generated identifier for the comparable lease transaction record used as market evidence in valuation analysis.',
    `appraisal_id` BIGINT COMMENT 'Reference to the parent valuation engagement or appraisal report for which this comparable lease record was selected as market evidence.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: Comparable lease rent PSF calculations and lease size measurements require a defined area measurement standard (BOMA, IPMS, RICS). The plain area_measurement_standard column is denormalized; normalizi',
    `asset_id` BIGINT COMMENT 'Reference to the subject or comparable property in the property master record. Used to link the comp to a known property asset in the portfolio or market database.',
    `bpo_id` BIGINT COMMENT 'Foreign key linking to valuation.bpo. Business justification: BPOs for income-producing properties use comparable lease transactions as market evidence for rental income assumptions. comparable_lease already has appraisal_id for appraisal-linked lease comps. Add',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: Comparable leases are filtered by building class (A/B/C) as a primary selection criterion in the income approach — Class A office rents differ materially from Class B. The comparable_lease product has',
    `cma_id` BIGINT COMMENT 'Foreign key linking to valuation.cma. Business justification: CMAs for rental properties use comparable lease transactions to estimate market rent and support the recommended list price or value range. Adding cma_id (nullable) to comparable_lease allows lease co',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Comparable lease rent figures (base_rent_psf, effective_rent_psf, ti_allowance_psf, cam_charges_psf) are currency-denominated. Normalizing the plain currency_code column to a FK supports cross-border ',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: Comparable leases are submarket-specific; the submarket plain column is a denormalized geographic hierarchy reference. Normalizing to a FK enables structured submarket-level rent comparability analysi',
    `approach_id` BIGINT COMMENT 'Foreign key linking to valuation.valuation_approach. Business justification: The income capitalization approach (valuation_approach with approach_type = INCOME) relies on comparable lease transactions to support the concluded market rent PSF. Adding income_approach_id (nulla',
    `industry_classification_id` BIGINT COMMENT 'Foreign key linking to reference.industry_classification. Business justification: Comparable lease tenant industry classification (NAICS/SIC) is critical for credit risk assessment, lease comparability analysis, and retail tenant mix evaluation. The plain tenant_industry column is ',
    `lease_agreement_id` BIGINT COMMENT 'Foreign key linking to lease.agreement. Business justification: Appraisal Comparable Lease Sourcing: when an appraiser uses an in-system executed lease as a rent comparable, the comparable_lease record should reference the actual lease.agreement. Enables appraiser',
    `market_survey_id` BIGINT COMMENT 'Foreign key linking to marketing.market_survey. Business justification: Comparable lease comps are validated against market survey benchmarks for avg_ti_allowance_psf, avg_free_rent_months, and avg_asking_rent_psf. Appraisers link comp leases to the market survey that pro',
    `occupancy_id` BIGINT COMMENT 'Foreign key linking to tenant.occupancy. Business justification: Appraisal comparable lease sourcing: appraisers use internal portfolio lease data as comparable evidence in income-approach valuations. Linking comparable_lease to the occupancy record traces the comp',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: Comparable leases are property-type-specific; office, retail, and industrial leases use different rent structures, TI benchmarks, and adjustment factors. The plain property_type column is denormalized',
    `lease_type_id` BIGINT COMMENT 'Foreign key linking to reference.lease_type. Business justification: Comparable lease rent comparability and adjustment methodology depend fundamentally on lease type (NNN, gross, modified gross). The plain lease_type column is denormalized; normalizing to a FK enables',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Income-approach rent comparables in commercial appraisals reference specific leased spaces. When the comparable is an in-portfolio space, linking comparable_lease to property.space enables direct rent',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: Comparable leases are for specific space use types (office, retail, industrial, medical) which drives rent comparability, TI allowance benchmarks, CAM structures, and load factor adjustments. Linking ',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Residential rent comparables in appraisals and CMAs reference specific units. comparable_lease links to asset but not unit. For multifamily income-approach appraisals, tying rent comps to specific in-',
    `adjusted_rent_psf` DECIMAL(18,2) COMMENT 'Base rent per square foot after applying all grid adjustments (time, location, condition, size, etc.) to normalize the comparable lease to the subject property characteristics. The final adjusted rent used in market rent conclusions.',
    `analyst_notes` STRING COMMENT 'Free-text field for appraiser or analyst commentary on the comparable lease, including any unusual terms, market conditions at time of execution, or qualitative factors affecting comparability. Supports USPAP narrative appraisal report requirements.',
    `base_rent_psf` DECIMAL(18,2) COMMENT 'Annual base rent expressed on a per-square-foot (PSF) basis for the comparable lease. The primary rent metric used in income capitalization and market rent conclusions. Classified as confidential due to commercially sensitive deal terms.',
    `cam_charges_psf` DECIMAL(18,2) COMMENT 'Common Area Maintenance (CAM) charges expressed on a per-square-foot annual basis for the comparable lease. Used to gross up NNN rents to a gross equivalent for cross-lease comparisons.',
    `city` STRING COMMENT 'City in which the comparable property is located. Used for geographic market segmentation and submarket assignment.',
    `comp_property_address` STRING COMMENT 'Full street address of the comparable property including street number, street name, suite or floor where applicable. Used for geographic proximity analysis in market rent conclusions.',
    `comp_property_name` STRING COMMENT 'Common or marketing name of the comparable property (e.g., One Embarcadero Center, Westfield Mall). Used for identification and reporting in valuation narratives.',
    `comp_reference_number` STRING COMMENT 'Externally-known identifier or deal reference number assigned to this comparable lease transaction, as sourced from CoStar, MLS, or direct broker confirmation. Serves as the business-facing unique code for the comp record.',
    `condition_adjustment_pct` DECIMAL(18,2) COMMENT 'Percentage adjustment applied to the comparable lease rent to account for differences in building condition, quality, or finish level between the comparable and subject properties.',
    `costar_property_reference` STRING COMMENT 'CoStar Suites unique property identifier for the comparable property. Enables direct cross-reference to CoStar market data for automated comp retrieval and market analytics.',
    `data_source` STRING COMMENT 'Primary source from which the comparable lease transaction data was obtained (e.g., CoStar Suite, MLS, direct landlord/tenant confirmation, broker, public record). Determines the reliability tier of the comp in IVSC-compliant methodology documentation.. Valid values are `CoStar|MLS|direct|broker|public record|appraiser`',
    `effective_rent_psf` DECIMAL(18,2) COMMENT 'Net effective rent per square foot after accounting for free rent periods, tenant improvement allowances, and other landlord concessions amortized over the lease term. Provides a true economic rent comparison across leases with varying concession packages.',
    `expansion_option_flag` BOOLEAN COMMENT 'Indicates whether the comparable lease includes a tenant expansion option for additional space. Relevant for assessing tenant demand and flexibility provisions in market analysis.',
    `free_rent_months` DECIMAL(18,2) COMMENT 'Number of months of rent abatement (free rent) granted to the tenant at lease commencement. A landlord concession that reduces effective rent; used to normalize comparable leases to a common economic basis.',
    `lease_commencement_date` DATE COMMENT 'Date on which the comparable lease term officially commenced and the tenant took occupancy or began paying rent. Used to determine the effective market date and calculate free rent periods.',
    `lease_execution_date` DATE COMMENT 'Date on which the comparable lease agreement was fully executed (signed) by both landlord and tenant. Establishes the market date for the transaction, critical for time-adjustment analysis in income approach valuations.',
    `lease_expiration_date` DATE COMMENT 'Scheduled expiration date of the comparable lease term. Used in conjunction with commencement date to validate the stated lease term in months.',
    `lease_size_sqf` DECIMAL(18,2) COMMENT 'Total leased area of the comparable lease expressed in square feet (SQF). Used to assess scale comparability with the subject property and to weight rent conclusions in market analysis.',
    `lease_size_sqm` DECIMAL(18,2) COMMENT 'Total leased area of the comparable lease expressed in square meters (SQM). Used for international market comparisons and IVSC-compliant valuation reports.',
    `lease_term_months` STRING COMMENT 'Total duration of the comparable lease expressed in months from commencement to expiration. A key comparability factor in market rent analysis; longer terms typically command lower effective rents.',
    `location_adjustment_pct` DECIMAL(18,2) COMMENT 'Percentage adjustment applied to the comparable lease rent to account for locational differences between the comparable and subject properties. Part of the grid adjustment methodology in income approach valuations.',
    `operating_expense_stop_psf` DECIMAL(18,2) COMMENT 'Base year operating expense stop per square foot above which the tenant is responsible for expense increases. Common in modified gross leases; used to normalize rent comparisons across different expense structures.',
    `postal_code` STRING COMMENT 'Postal or ZIP code of the comparable property location. Supports geographic clustering and submarket boundary analysis.',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this comparable lease record was first created in the system. Supports data lineage, audit trail, and Silver layer ingestion tracking in the Databricks Lakehouse.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this comparable lease record was last modified. Supports change tracking, data quality monitoring, and audit trail requirements in the Silver layer.',
    `renewal_option_flag` BOOLEAN COMMENT 'Indicates whether the comparable lease includes one or more tenant renewal options. Presence of renewal options affects the economic value of the lease and is noted in market rent analysis.',
    `renewal_option_term_months` STRING COMMENT 'Duration in months of each renewal option period available to the tenant under the comparable lease. Used to assess the total potential lease commitment and WALT calculations.',
    `rent_escalation_rate` DECIMAL(18,2) COMMENT 'Annual rent escalation rate expressed as a decimal (e.g., 0.03 for 3%) applicable to fixed or percentage-based escalation structures. Used in Argus Enterprise DCF models to project future rent cash flows.',
    `rent_escalation_type` STRING COMMENT 'Method by which base rent escalates over the lease term (e.g., fixed annual percentage, CPI-linked, stepped increases, or flat). Used to assess the economic profile of the comparable lease in DCF-based valuation models.. Valid values are `fixed|CPI|percentage|stepped|none`',
    `state_province` STRING COMMENT 'State or province in which the comparable property is located. Used for regulatory jurisdiction mapping and geographic market analysis.',
    `ti_allowance_psf` DECIMAL(18,2) COMMENT 'Tenant Improvement (TI) allowance provided by the landlord expressed on a per-square-foot basis. A key concession metric used to normalize comparable leases and assess true economic rent in income approach valuations.',
    `time_adjustment_pct` DECIMAL(18,2) COMMENT 'Percentage adjustment applied to the comparable lease rent to account for market conditions between the lease execution date and the valuation date. Used in the sales comparison and income approaches to normalize historical comps to current market.',
    `verification_date` DATE COMMENT 'Date on which the comparable lease transaction data was verified through a reliable source. Required for IVSC-compliant methodology documentation and appraisal report quality control.',
    `verification_status` STRING COMMENT 'Current verification state of the comparable lease data indicating whether the transaction details have been confirmed through a reliable source such as broker confirmation, public record, or direct tenant/landlord contact. Drives reliability weighting in rent analysis.. Valid values are `unverified|pending|verified|rejected`',
    CONSTRAINT pk_comparable_lease PRIMARY KEY(`comparable_lease_id`)
) COMMENT 'Comparable lease transaction record used as market evidence in income capitalization and rent analysis. Stores comp property address, tenant name, lease execution date, lease commencement date, lease term (months), base rent PSF, rent type (NNN, gross, modified gross), TI allowance PSF, free rent period, lease size (SQF/SQM), property class, submarket, data source (CoStar, MLS, direct), and verification status. Supports market rent conclusions in income approach valuations.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`approach` (
    `approach_id` BIGINT COMMENT 'Primary key for approach',
    `appraisal_id` BIGINT COMMENT 'Reference to the parent valuation engagement or appraisal report to which this approach record belongs. Links the approach to its overarching valuation assignment.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: Approach outputs (concluded_market_rent_psf, replacement_cost_new) are expressed per area unit; the UOM reference ensures consistent measurement standards across cross-border portfolios. IVSC and RICS',
    `asset_id` BIGINT COMMENT 'Reference to the subject property being valued under this approach. Ties the valuation approach to the specific real estate asset in the property master record.',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: Valuation approaches are calibrated by building class which affects cap rates, depreciation rates, and market rent benchmarks. The income approach and cost approach produce materially different output',
    `cap_rate_benchmark_id` BIGINT COMMENT 'Foreign key linking to valuation.cap_rate_benchmark. Business justification: valuation_approach uses cap_rate in direct capitalization. The applied cap rate should be benchmarked against market data. Adding cap_rate_benchmark_id links the approach model to the market benchmark',
    `construction_type_id` BIGINT COMMENT 'Foreign key linking to reference.construction_type. Business justification: The cost approach requires construction type to determine replacement_cost_new, depreciation method, and useful economic life. USPAP cost approach methodology explicitly requires construction type cla',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Valuation approach financial outputs (concluded_value, pgi, egi, noi, land_value, replacement_cost_new) are currency-denominated. Normalizing to a FK enables consistent currency handling in multi-curr',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: Valuation approaches require submarket-level geographic context for market rent benchmarking and cap rate selection. The income approach uses submarket vacancy rates and rent growth assumptions; geogr',
    `lease_type_id` BIGINT COMMENT 'Foreign key linking to reference.lease_type. Business justification: The income approach requires lease type classification to determine expense recovery structure, effective gross income, and NOI. NNN vs gross lease structures produce materially different NOI calculat',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to reference.market_segment. Business justification: Valuation approaches are calibrated to specific investment market segments (core, value-add, opportunistic) which determines discount rates, hold period assumptions, and investor return expectations. ',
    `market_survey_id` BIGINT COMMENT 'Foreign key linking to marketing.market_survey. Business justification: Income approach and sales comparison approach valuations rely on market survey data for concluded_market_rent_psf, vacancy_credit_loss_rate, and pgi inputs. Appraisers cite the specific market survey ',
    `noi_statement_id` BIGINT COMMENT 'Foreign key linking to finance.noi_statement. Business justification: The income approach in valuation_approach uses NOI as its primary input. Linking to the authoritative NOI statement documents the source of the NOI figure used in the income approach, supporting USPAP',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to property.parcel. Business justification: The land residual and cost approaches in appraisals require direct reference to the parcel for land value extraction. Approach links to asset but not parcel. For land valuation and development feasibi',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: Valuation approach parameters (cap rate, GRM, cost indices, depreciation rates) are property-type-specific. A domain expert would expect the income, sales comparison, and cost approaches to reference ',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Valuation approaches for commercial leasehold interests are applied at the space level. The income approach for a specific suite requires space-level rent and area data. Approach links to asset but no',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: Income and cost approaches are calibrated differently by space use type (office vs retail vs industrial vs multifamily). Space use type drives concluded_market_rent_psf, load_factor, and expense recov',
    `transaction_type_id` BIGINT COMMENT 'Foreign key linking to reference.transaction_type. Business justification: Valuation approaches are prepared for specific transaction types (sale, financing, estate, litigation) which determines the standard of value and methodology applied. USPAP requires the intended trans',
    `approach_date` DATE COMMENT 'Effective date as of which the valuation approach analysis is performed. Represents the appraisal effective date for this specific methodology, which may differ from the report date.',
    `approach_status` STRING COMMENT 'Current lifecycle state of this valuation approach record within the appraisal workflow. Tracks progression from initial draft through peer review, approval, and potential supersession by a revised approach.. Valid values are `draft|in_review|approved|superseded|rejected`',
    `approach_type` STRING COMMENT 'Discriminator identifying the valuation methodology applied in this record. Supported types: direct_cap (Direct Capitalization), DCF (Discounted Cash Flow), cost (Cost Approach), sales_comparison (Sales Comparison Approach), GRM (Gross Rent Multiplier). Drives which set of methodology-specific fields are populated.. Valid values are `direct_cap|DCF|cost|sales_comparison|GRM`',
    `approved_date` DATE COMMENT 'Date on which this valuation approach was formally approved by the reviewing appraiser or valuation committee. Marks the transition from in_review to approved status in the approach lifecycle.',
    `argus_model_reference` STRING COMMENT 'Reference identifier or file path for the Argus Enterprise cash flow model associated with this DCF valuation approach. Enables traceability back to the source Argus model for audit, review, and replication purposes. Populated for DCF approach type.',
    `cap_rate` DECIMAL(18,2) COMMENT 'Overall capitalization rate (CAP rate) applied to stabilized NOI to derive the direct capitalization value. Expressed as a decimal (e.g., 0.0550 = 5.50%). Derived from market comparable sales analysis and reflects investor return expectations for the asset class and submarket.',
    `comparable_count` STRING COMMENT 'Number of comparable sales or lease transactions used to support the approach inputs (e.g., CAP rate derivation for direct cap, market rent for income approaches, adjusted sales for sales comparison). Indicates the depth of market evidence supporting the concluded value.',
    `concluded_market_rent_psf` DECIMAL(18,2) COMMENT 'Appraisers concluded market rent per square foot (PSF) used as the basis for PGI estimation in income capitalization approaches. Derived from comparable lease analysis and market surveys. Expressed in the reporting currency per square foot per year.',
    `concluded_value` DECIMAL(18,2) COMMENT 'The indicated market value produced by this specific valuation approach before reconciliation weighting. Represents the raw output of the methodology (e.g., direct capitalization value, DCF NPV, depreciated cost, or sales comparison adjusted value) in the reporting currency.',
    `cost_index_source` STRING COMMENT 'Source of the construction cost index or cost manual used to estimate RCN in the cost approach. Common sources include Marshall & Swift Valuation Service and RSMeans Cost Data. Supports methodology transparency and IVSC IVS 105 compliance documentation.. Valid values are `Marshall_Swift|RSMeans|local_contractor|other`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp recording when this valuation approach record was first created in the system. Supports audit trail, data lineage, and SOX financial controls for valuation records used in financial reporting.',
    `depreciated_cost_of_improvements` DECIMAL(18,2) COMMENT 'Net value of the improvements after deducting total accrued depreciation (physical, functional, and external obsolescence) from RCN. Added to land value to derive the cost approach indicated value. Populated for cost approach type.',
    `direct_cap_value` DECIMAL(18,2) COMMENT 'Indicated value derived by dividing stabilized NOI by the overall CAP rate (NOI / CAP Rate). Represents the concluded value under the direct capitalization method. Populated only when approach_type = direct_cap.',
    `discount_rate` DECIMAL(18,2) COMMENT 'Risk-adjusted discount rate (expressed as a decimal) used in the DCF analysis to convert projected future cash flows to present value. Reflects the required rate of return for the investment, incorporating market risk, asset type, and leverage. Populated for DCF approach type.',
    `economic_life_years` STRING COMMENT 'Total estimated economic life of the improvements in years — the period over which the building is expected to contribute positively to property value. Used with effective age to calculate the age-life depreciation ratio in the cost approach.',
    `effective_age_years` STRING COMMENT 'Appraisers estimate of the effective age of the improvements in years, reflecting the actual condition and utility of the building relative to a new structure of similar type. May differ from chronological age due to renovations or deferred maintenance. Used in cost approach depreciation calculations.',
    `egi` DECIMAL(18,2) COMMENT 'Effective Gross Income — PGI adjusted for vacancy, credit loss, and other income (e.g., parking, ancillary revenue). Represents the realistic annual income the property is expected to generate. Populated for direct_cap and DCF approach types.',
    `external_obsolescence` DECIMAL(18,2) COMMENT 'Loss in value caused by factors external to the property, such as adverse market conditions, neighborhood decline, or proximity to negative influences. Also known as economic obsolescence. Deducted from RCN in the cost approach.',
    `functional_obsolescence` DECIMAL(18,2) COMMENT 'Loss in value resulting from deficiencies or superadequacies in the design, layout, or functionality of the improvements relative to current market standards (e.g., outdated floor plans, inadequate HVAC systems). Deducted from RCN in the cost approach.',
    `grm` DECIMAL(18,2) COMMENT 'Gross Rent Multiplier — the ratio of property value to gross annual (or monthly) rental income, derived from comparable sales. Applied to the subject propertys gross rent to estimate value under the GRM approach. Populated when approach_type = GRM.',
    `hold_period_years` STRING COMMENT 'Projected investment hold period in years used in the DCF analysis. Defines the number of annual cash flow periods modeled before the terminal reversion value is calculated. Typically ranges from 5 to 15 years for commercial real estate. Populated for DCF approach type.',
    `irr` DECIMAL(18,2) COMMENT 'Internal Rate of Return — the discount rate at which the net present value of all projected cash flows (including acquisition cost and terminal reversion) equals zero. Key investment performance metric output from the DCF model. Populated for DCF approach type.',
    `ivsc_methodology_code` STRING COMMENT 'IVSC IVS 105 methodology classification code identifying the specific valuation technique applied (e.g., IVS105-IC for Income Capitalization, IVS105-CA for Cost Approach, IVS105-SC for Sales Comparison). Supports regulatory compliance documentation and cross-border reporting.',
    `land_value` DECIMAL(18,2) COMMENT 'Estimated market value of the land component as if vacant and available for its highest and best use. Used in the cost approach as the foundation to which depreciated cost of improvements is added. Populated for cost approach type.',
    `methodology_notes` STRING COMMENT 'Free-text field capturing appraiser commentary on the rationale, assumptions, limitations, and adjustments specific to this valuation approach. Supports IVSC IVS 105 compliance, USPAP disclosure requirements, and peer review documentation.',
    `noi` DECIMAL(18,2) COMMENT 'Net Operating Income — EGI minus total OPEX. The primary income metric used in direct capitalization and DCF valuation. Represents the annual pre-debt, pre-tax cash flow generated by the property. Populated for direct_cap and DCF approach types.',
    `npv` DECIMAL(18,2) COMMENT 'Net Present Value — the sum of all discounted future cash flows minus the initial investment cost, as output by the DCF model. A positive NPV indicates value creation above the required return. Populated for DCF approach type.',
    `pgi` DECIMAL(18,2) COMMENT 'Potential Gross Income — the maximum annual rental revenue the property could generate at 100% occupancy at market rent. Used as the starting point for income capitalization approaches (direct cap and DCF). Populated for direct_cap and DCF approach types.',
    `physical_depreciation` DECIMAL(18,2) COMMENT 'Loss in value attributable to physical deterioration of the improvements, including curable deferred maintenance and incurable structural wear. Deducted from RCN in the cost approach. Populated for cost approach type.',
    `rent_basis` STRING COMMENT 'Basis on which the concluded market rent is expressed. Indicates whether the rent is annual or monthly and the lease structure (NNN — Triple Net, gross, or modified gross) that underpins the income analysis.. Valid values are `annual|monthly|NNN|gross|modified_gross`',
    `replacement_cost_new` DECIMAL(18,2) COMMENT 'Replacement Cost New (RCN) — the estimated cost to construct a building of equivalent utility using current materials, standards, and design at current prices. Starting point for the cost approach before depreciation deductions. Populated for cost approach type.',
    `sensitivity_notes` STRING COMMENT 'Narrative description of key sensitivity scenarios tested for this approach, such as the impact of a 25 bps change in CAP rate or discount rate on concluded value. Supports investment decision-making and risk disclosure in appraisal reports.',
    `terminal_cap_rate` DECIMAL(18,2) COMMENT 'Reversion or terminal CAP rate applied to the projected NOI in the final year of the hold period to estimate the propertys residual (terminal) value in a DCF analysis. Typically higher than the going-in CAP rate to reflect future uncertainty. Populated for DCF approach type.',
    `total_opex` DECIMAL(18,2) COMMENT 'Total annual operating expenses (OPEX) for the subject property, including property taxes, insurance, management fees, maintenance, utilities, and reserves for replacement. Deducted from EGI to derive NOI. Populated for income capitalization approaches.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp recording the most recent modification to this valuation approach record. Used for change tracking, audit compliance, and incremental data pipeline processing in the Databricks Silver Layer.',
    `vacancy_credit_loss_rate` DECIMAL(18,2) COMMENT 'Estimated rate (decimal fraction) applied to PGI to account for expected vacancy and uncollectible rent. For example, 0.05 represents a 5% vacancy and credit loss allowance. Used in income capitalization to derive EGI from PGI.',
    `weight_pct` DECIMAL(18,2) COMMENT 'Weighting factor (expressed as a decimal between 0 and 1) assigned to this approach in the final value reconciliation. For example, 0.60 indicates this approach contributes 60% to the concluded value. All approach weights for a given valuation should sum to 1.0.',
    CONSTRAINT pk_approach PRIMARY KEY(`approach_id`)
) COMMENT 'Valuation approach model record capturing the quantitative analysis for income capitalization and cost approach methodologies. For income capitalization: stores PGI, vacancy/credit loss rate, EGI, total OPEX, NOI, CAP rate, direct capitalization value, terminal CAP rate, discount rate, hold period, IRR/NPV outputs, and concluded market rent inputs. For cost approach: stores land value, replacement cost new (RCN), depreciation components (physical, functional, external obsolescence), depreciated cost of improvements, effective age, economic life, and cost index source (Marshall & Swift, RSMeans). Includes approach type discriminator (direct_cap, DCF, cost, sales_comparison, GRM) and approach weight in final reconciliation. Supports IVSC IVS 105 compliance. After merge with cost_approach, this is the unified approach model for all valuation methodologies.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`dcf_model` (
    `dcf_model_id` BIGINT COMMENT 'Unique surrogate identifier for the DCF model record in the Silver Layer lakehouse. Primary key for the valuation_dcf_model product.',
    `appraisal_id` BIGINT COMMENT 'Foreign key linking to valuation.appraisal. Business justification: A DCF model is frequently prepared as part of a formal appraisal engagement in real estate investment analysis. Linking dcf_model.appraisal_id to appraisal establishes the parent engagement context fo',
    `approach_id` BIGINT COMMENT 'Foreign key linking to valuation.approach. Business justification: The approach table captures income capitalization and cost approach models. A DCF model is a specific, detailed implementation of the income approach. Linking dcf_model.approach_id to approach.approac',
    `assessment_id` BIGINT COMMENT 'Foreign key linking to compliance.assessment. Business justification: DCF models used in fund reporting are subject to fair value compliance assessments (ASC 820, AIFMD). The compliance assessment validates model methodology and assumptions. Investment managers referenc',
    `asset_id` BIGINT COMMENT 'Reference to the subject property being underwritten or valued through this DCF model.',
    `brokerage_deal_id` BIGINT COMMENT 'Foreign key linking to brokerage.brokerage_deal. Business justification: DCF models are built to evaluate specific acquisition or disposition deals for investment committee approval. The deal that the DCF supports must be traceable for deal underwriting records, investment',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: DCF models incorporate budgeted income and expense assumptions. Asset managers compare DCF projections against the approved finance budget to assess underwriting accuracy, a standard investment commit',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: DCF models use building class to calibrate rent growth rates, vacancy assumptions, and terminal cap rates. Class A assets command different going-in cap rates and rent growth assumptions than Class B/',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: DCF models in commercial RE are built at the building level — rent roll, lease expirations, capex_reserve_psf, and NLA are all building-specific inputs. Argus Enterprise models are structured around b',
    `cap_rate_benchmark_id` BIGINT COMMENT 'Foreign key linking to valuation.cap_rate_benchmark. Business justification: valuation_dcf_model uses going_in_cap_rate and terminal_cap_rate assumptions. These should be benchmarked against market cap rate data. Adding cap_rate_benchmark_id links the DCF model to the market b',
    `capex_project_id` BIGINT COMMENT 'Foreign key linking to maintenance.capex_project. Business justification: DCF models explicitly incorporate capex_reserve_psf and capital improvement timelines. Institutional underwriters link the DCF model to the specific capex_project driving those assumptions for audit t',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: DCF models are built for assets whose operating cash flows are tracked through cost centers. Linking DCF model to cost center enables direct comparison of modeled vs. actual NOI by cost center, a stan',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: DCF model financial outputs (acquisition_price, equity_investment, debt_amount, npv, reversion_value) are currency-denominated. Normalizing the plain currency_code column to a FK is required for multi',
    `debt_instrument_id` BIGINT COMMENT 'Foreign key linking to finance.debt_instrument. Business justification: Leveraged DCF models incorporate actual loan terms (interest rate, amortization, LTV) from specific debt instruments. The model has `debt_amount` and `ltv_ratio` as manual inputs; linking to the actua',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: Development underwriting requires a DCF model to project construction costs, lease-up, stabilized NOI, and exit value for each dev_project. Lenders and investment committees require a project-level DC',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: DCF model assumptions (rent growth rate, vacancy rate, exit cap rate) are submarket-specific. Linking to geographic_hierarchy enables submarket-level DCF assumption validation, market-driven sensitivi',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction. Business justification: DCF models incorporate jurisdiction-specific tax treatment, depreciation rules, and regulatory hold-period constraints that directly affect IRR and NPV outputs. Investment analysts and compliance team',
    `lease_type_id` BIGINT COMMENT 'Foreign key linking to reference.lease_type. Business justification: DCF models for income-producing properties require lease type to model expense recovery, NOI, and cash flow projections. NNN vs gross lease structures produce materially different levered_irr and equi',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: DCF models are built from ledger-specific financial data (GAAP vs. IFRS vs. tax basis). Knowing which ledger the models income and expense inputs derive from is essential for audit and investment com',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to reference.market_segment. Business justification: DCF model assumptions (discount rate, terminal cap rate, hold period, leverage) are calibrated to investment strategy. The market_segment defines target IRR ranges, LTV limits, and hold periods that v',
    `market_survey_id` BIGINT COMMENT 'Foreign key linking to marketing.market_survey. Business justification: DCF models use market survey data for rent_growth_rate, vacancy_rate_assumption, and market rent benchmarks. The model_assumptions_narrative must cite the market survey used. Argus Enterprise models e',
    `occupancy_record_id` BIGINT COMMENT 'Foreign key linking to property.occupancy_record. Business justification: DCF models use occupancy data as the baseline for revenue projections. dcf_model.vacancy_rate_assumption is a denormalized plain attribute. Linking to occupancy_record identifies the specific occupanc',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to property.parcel. Business justification: DCF models for land development projects are tied to specific parcels (entitlement value, land carry costs). DCF links to asset and building but not parcel. Development feasibility DCFs require parcel',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: DCF models are built for specific property types which drive rent growth rates, vacancy assumptions, and terminal cap rate selection. Argus Enterprise and similar DCF platforms require property type a',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: DCF models used for REIT reporting, fund NAV, or SEC filings must comply with specific regulatory obligations (ASC 820 fair value hierarchy, SEC Regulation S-X, INREV guidelines). Compliance teams tra',
    `reporting_period_id` BIGINT COMMENT 'Foreign key linking to finance.reporting_period. Business justification: DCF models are versioned and approved within specific reporting periods for investment committee presentations and lender reporting. Linking to reporting_period enables period-over-period model compar',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: DCF models are calibrated by space use type (office, retail, industrial, multifamily) which drives lease-up assumptions, market rent inputs, and expense recovery modeling. Argus Enterprise requires sp',
    `transaction_type_id` BIGINT COMMENT 'Foreign key linking to reference.transaction_type. Business justification: DCF models are prepared for specific transaction types (acquisition, disposition, refinance, joint venture) which determines the modeling perspective, equity structure, and return metrics reported. mo',
    `acquisition_price` DECIMAL(18,2) COMMENT 'Total assumed purchase price of the property at the start of the hold period, used as the basis for LTV, equity multiple, and IRR calculations.',
    `approval_date` DATE COMMENT 'The date on which this DCF model was formally approved by the designated reviewer or investment committee. Required for SOX audit trail and governance compliance.',
    `argus_model_reference` STRING COMMENT 'Native model identifier assigned by Argus Enterprise to the source cash flow model file. Used to trace back to the originating Argus Enterprise model for audit and reconciliation.',
    `argus_model_version` STRING COMMENT 'Version label of the Argus Enterprise model file (e.g., v1.0, v2.3-final) to distinguish iterative revisions of the same model.',
    `avg_dscr` DECIMAL(18,2) COMMENT 'Average annual Debt Service Coverage Ratio across the hold period, calculated as NOI divided by annual debt service. Lenders typically require a minimum DSCR of 1.20x–1.25x.',
    `capex_reserve_psf` DECIMAL(18,2) COMMENT 'Annual capital expenditure reserve amount per square foot budgeted for building improvements, tenant improvements (TI), and leasing commissions over the hold period.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this DCF model record was first created in the lakehouse Silver Layer. Supports audit trail and data lineage tracking.',
    `debt_amount` DECIMAL(18,2) COMMENT 'Total debt (mortgage or loan) assumed at acquisition used to finance the property purchase. Drives LTV and DSCR calculations within the model.',
    `discount_rate` DECIMAL(18,2) COMMENT 'The target Internal Rate of Return (IRR) used as the discount rate to compute Net Present Value (NPV) of projected cash flows. Reflects the required return on investment for this asset.',
    `equity_investment` DECIMAL(18,2) COMMENT 'Total equity capital contributed at acquisition, representing the difference between acquisition price and debt financing. Used to compute levered IRR and equity multiple.',
    `equity_multiple` DECIMAL(18,2) COMMENT 'Total equity distributions (cash flows plus net reversion proceeds) divided by total equity invested. An equity multiple of 2.0x means the investor doubles their equity over the hold period.',
    `expense_growth_rate` DECIMAL(18,2) COMMENT 'Assumed annual percentage increase in operating expenses (OPEX) applied across the projection period. Typically benchmarked to CPI or market inflation indices.',
    `going_in_cap_rate` DECIMAL(18,2) COMMENT 'The capitalization rate implied by the acquisition price and Year 1 NOI. Used to benchmark the entry pricing against market comparables and assess acquisition risk.',
    `hold_period_end_date` DATE COMMENT 'The date on which the modeled investment hold period ends, representing the assumed disposition or reversion date.',
    `hold_period_start_date` DATE COMMENT 'The date on which the modeled investment hold period commences, typically the assumed acquisition or ownership transfer date.',
    `hold_period_years` STRING COMMENT 'Total duration of the modeled investment hold period expressed in whole years (e.g., 10 for a 10-year hold). Drives the number of annual cash flow projection periods.',
    `is_levered` BOOLEAN COMMENT 'Indicates whether this DCF model incorporates debt financing (levered analysis). True = levered model with debt service; False = unlevered all-equity model.',
    `levered_irr` DECIMAL(18,2) COMMENT 'The Internal Rate of Return computed on levered (equity) cash flows after debt service. Reflects the actual return to equity investors accounting for financial leverage.',
    `ltv_ratio` DECIMAL(18,2) COMMENT 'Ratio of the debt amount to the acquisition price at the time of underwriting, expressed as a decimal (e.g., 0.65 for 65% LTV). Key metric for lender and investor risk assessment.',
    `methodology_standard` STRING COMMENT 'The governing valuation methodology standard applied in constructing this DCF model. Ensures compliance with applicable appraisal and financial reporting frameworks.. Valid values are `IVSC_IVS|USPAP|RICS_RED_BOOK|TEGoVA_EVS|FASB_ASC820`',
    `min_dscr` DECIMAL(18,2) COMMENT 'The lowest annual DSCR observed across all projection periods in the hold period. Identifies the most stressed year for debt coverage, critical for lender covenant compliance.',
    `model_assumptions_narrative` STRING COMMENT 'Free-text narrative documenting the key assumptions, market conditions, data sources, and qualifications underlying this DCF model. Required for IVSC-compliant methodology disclosure and investment committee review.',
    `model_number` STRING COMMENT 'Human-readable business identifier for this DCF model record, formatted as DCF-YYYY-NNNNNN. Used in investment committee presentations, audit trails, and cross-system references.. Valid values are `^DCF-[0-9]{4}-[0-9]{6}$`',
    `model_purpose` STRING COMMENT 'Business purpose for which this DCF model was constructed. Determines the applicable methodology standards and reporting requirements. [ENUM-REF-CANDIDATE: acquisition_underwriting|disposition_analysis|refinancing|annual_valuation|portfolio_reporting|impairment_testing|loan_origination — promote to reference product]',
    `model_status` STRING COMMENT 'Current lifecycle state of the DCF model record. Controls which version is authoritative for investment decisions and financial reporting.. Valid values are `draft|in_review|approved|superseded|archived`',
    `net_reversion_proceeds` DECIMAL(18,2) COMMENT 'Gross reversion value less estimated selling costs, representing the net cash inflow to the investor upon disposition at the end of the hold period.',
    `npv_at_discount_rate` DECIMAL(18,2) COMMENT 'Net Present Value of all projected cash flows (including reversion) discounted at the models target discount rate. Positive NPV indicates value creation above the required return threshold.',
    `rent_growth_rate` DECIMAL(18,2) COMMENT 'Assumed annual percentage increase in market rents applied across the projection period. Drives revenue escalation in the DCF cash flow schedule.',
    `reversion_value` DECIMAL(18,2) COMMENT 'Estimated gross sale proceeds at the end of the hold period, calculated by applying the terminal cap rate to the projected NOI in the reversion year. Represents the largest single cash inflow in the DCF model.',
    `selling_costs_rate` DECIMAL(18,2) COMMENT 'Percentage of reversion value deducted for estimated disposition costs (brokerage commissions, transfer taxes, legal fees) to arrive at net reversion proceeds.',
    `sensitivity_irr_high` DECIMAL(18,2) COMMENT 'Levered IRR under the upside/bull case sensitivity scenario, reflecting optimistic assumptions (lower vacancy, higher rent growth, lower cap rate). Bounds the investment return range.',
    `sensitivity_irr_low` DECIMAL(18,2) COMMENT 'Levered IRR under the downside/bear case sensitivity scenario, reflecting stressed assumptions (higher vacancy, lower rent growth, higher cap rate). Used in investment committee risk analysis.',
    `stabilized_noi` DECIMAL(18,2) COMMENT 'Projected NOI at stabilized occupancy, representing the normalized income potential of the property once lease-up or repositioning is complete. Used for terminal cap rate application.',
    `terminal_cap_rate` DECIMAL(18,2) COMMENT 'The capitalization rate applied to the final year Net Operating Income (NOI) to derive the reversion/terminal value at the end of the hold period. Critical assumption in DCF reversion calculation.',
    `unlevered_irr` DECIMAL(18,2) COMMENT 'The Internal Rate of Return computed on unlevered (all-equity, pre-financing) cash flows. Measures the intrinsic return of the asset independent of capital structure.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this DCF model record was most recently modified. Used to detect stale models and enforce model refresh policies.',
    `vacancy_rate_assumption` DECIMAL(18,2) COMMENT 'Blended vacancy and credit loss rate applied to Potential Gross Income (PGI) to derive Effective Gross Income (EGI) in the model. Expressed as a decimal (e.g., 0.05 for 5%).',
    `valuation_date` DATE COMMENT 'The effective date as of which the DCF model value conclusion is stated. This is the principal real-world event date for the model, distinct from the model creation or approval date.',
    `year1_noi` DECIMAL(18,2) COMMENT 'Projected Net Operating Income for the first year of the hold period, representing Effective Gross Income (EGI) less operating expenses. Foundational input for going-in cap rate and debt sizing.',
    CONSTRAINT pk_dcf_model PRIMARY KEY(`dcf_model_id`)
) COMMENT 'Discounted Cash Flow model record linked to an Argus Enterprise model file. Stores Argus model ID, model version, hold period start and end dates, annual cash flow projections (year 1–10+), reversion/terminal value, discount rate (IRR target), NPV at various discount rates, levered vs. unlevered IRR, equity multiple, DSCR per period, LTV at acquisition, and model assumptions narrative. Serves as the quantitative backbone for investment-grade valuations and acquisition underwriting.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`cap_rate_benchmark` (
    `cap_rate_benchmark_id` BIGINT COMMENT 'Unique surrogate identifier for each CAP rate benchmark record in the Silver Layer lakehouse. Primary key for this entity.',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: Cap rate benchmarks are segmented by building class (Class A, B, C) alongside property type; the asset_class plain column is a denormalized building class reference. Normalizing to a FK enables struct',
    `country_id` BIGINT COMMENT 'Foreign key linking to reference.country. Business justification: Cap rate benchmarks are country-specific for international real estate portfolios; the plain country_code column is a denormalized country reference. Normalizing to a FK enables country-level benchmar',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Cap rate benchmark NOI and value PSF figures (noi_psf_low/high, implied_value_psf_low/high) are currency-denominated. Normalizing the plain currency_code column to a FK enables cross-currency benchmar',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: Cap rate benchmarks are defined by submarket/MSA; the submarket_name, msa_name, msa_code, and state_code plain columns are all denormalized geographic hierarchy fields. Normalizing to a FK enables str',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction. Business justification: Cap rate benchmarks are jurisdiction-specific market data used in regulated fund reporting (NCREIF, GRESB, SEC). Compliance teams need jurisdiction context to validate that benchmarks used in appraisa',
    `lease_type_id` BIGINT COMMENT 'Foreign key linking to reference.lease_type. Business justification: Cap rate benchmarks are segmented by lease type (NNN vs gross) in commercial real estate surveys — NNN retail trades at materially different cap rates than gross office. CBRE and JLL cap rate reports ',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to reference.market_segment. Business justification: Cap rate benchmarks are segmented by investment strategy (core, value-add, opportunistic); institutional-grade core assets trade at different cap rates than value-add. Linking to market_segment enable',
    `market_survey_id` BIGINT COMMENT 'Foreign key linking to marketing.market_survey. Business justification: Cap rate benchmarks are derived from or corroborated by market surveys of investor sentiment and transaction activity. The cap_rate_benchmark.survey_methodology and source_organization fields indicate',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: Cap rate benchmarks are primarily organized by property type; this is the core classification axis for benchmark lookup in appraisals and DCF models. The plain property_type column is denormalized; no',
    `reporting_period_id` BIGINT COMMENT 'Foreign key linking to finance.reporting_period. Business justification: Cap rate benchmarks are published on a defined survey schedule (quarterly, annually). Linking to reporting_period enables time-series analysis of cap rate trends aligned with financial reporting perio',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: Cap rate benchmarks are segmented by space use type (office, retail, industrial, multifamily) as a primary dimension in CBRE, JLL, NCREIF, and MSCI cap rate surveys. Space use type is a finer-grained ',
    `analyst_notes` STRING COMMENT 'Free-text field for valuation analyst commentary on this benchmark record, including observations about market conditions, anomalies in the survey data, adjustments made during data ingestion, or guidance for appraisers on appropriate application of this benchmark.',
    `argus_model_reference` STRING COMMENT 'The reference identifier or file path of the Argus Enterprise valuation model that incorporates or was calibrated against this benchmark record. Enables traceability between market benchmark data and specific DCF/cash flow models used in investment analysis and portfolio reporting.',
    `benchmark_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this benchmark record, used for cross-system referencing and CoStar/Argus Enterprise integration (e.g., CRB-2024Q3-OFF-CLA-NYC). Serves as the business identifier for this benchmark.',
    `benchmark_status` STRING COMMENT 'Lifecycle status of this benchmark record indicating whether it is currently active for use in valuations, has been superseded by a newer survey, is in draft pending publication, archived for historical reference, or under review for accuracy.. Valid values are `active|superseded|draft|archived|under_review`',
    `cap_rate_high` DECIMAL(18,2) COMMENT 'The upper bound of the surveyed CAP rate range for this property type, asset class, and submarket combination, expressed as a decimal (e.g., 0.0650 = 6.50%). Represents the most conservative (highest) CAP rate observed, typically associated with lower-quality assets or less competitive submarkets.',
    `cap_rate_low` DECIMAL(18,2) COMMENT 'The lower bound of the surveyed CAP rate range for this property type, asset class, and submarket combination, expressed as a decimal (e.g., 0.0450 = 4.50%). Represents the most aggressive (lowest) CAP rate observed in the market, typically associated with the highest-quality assets or most competitive submarkets.',
    `cap_rate_mid` DECIMAL(18,2) COMMENT 'The midpoint or median of the surveyed CAP rate range, expressed as a decimal (e.g., 0.0550 = 5.50%). This is the primary benchmark value used by appraisers for CAP rate selection validation and by asset managers for NAV/GAV calculations in Argus Enterprise models.',
    `cap_rate_prior_mid` DECIMAL(18,2) COMMENT 'The midpoint CAP rate from the immediately preceding survey period for the same property type, asset class, and submarket. Used to calculate period-over-period movement and validate the trend_direction field. Supports time-series analysis in investment committee presentations.',
    `costar_market_reference` STRING COMMENT 'The CoStar Suite internal market identifier for the submarket or market area covered by this benchmark. Enables direct linkage to CoStar market analytics, comparable transaction data, and property analytics for benchmark validation and enrichment.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this benchmark record was first created and loaded into the Silver Layer lakehouse. Supports data lineage, audit trail, and record management in compliance with SOX financial controls and GDPR data governance requirements.',
    `data_quality_score` DECIMAL(18,2) COMMENT 'A numeric score (0.00–100.00) representing the assessed quality and reliability of this benchmark record based on sample size, source credibility, methodology transparency, and recency. Used by the data governance team to flag low-confidence benchmarks and by appraisers to weight multiple sources.',
    `effective_date` DATE COMMENT 'The date from which this benchmark record is considered valid and applicable for use in appraisals, NAV/GAV calculations, and investment committee presentations. May differ from survey_date if there is a publication lag.',
    `expiry_date` DATE COMMENT 'The date after which this benchmark record is no longer considered current and should not be used for new valuations without review. Typically set to the next expected survey publication date.',
    `implied_value_psf_high` DECIMAL(18,2) COMMENT 'The upper bound of the implied market value per square foot derived from the CAP rate range and prevailing NOI levels for this segment. Used in conjunction with implied_value_psf_low to establish a market value range for portfolio-level reporting.',
    `implied_value_psf_low` DECIMAL(18,2) COMMENT 'The lower bound of the implied market value per square foot derived from the CAP rate range and prevailing NOI levels for this segment. Provides a sanity-check metric for appraiser CAP rate selections and supports portfolio-level GAV/NAV estimation.',
    `investor_sentiment` STRING COMMENT 'The prevailing investor sentiment toward this property type and market segment as reported in the source survey (bullish, neutral, bearish). Provides qualitative market context for investment committee presentations and portfolio strategy discussions.. Valid values are `bullish|neutral|bearish`',
    `is_institutional_grade` BOOLEAN COMMENT 'Indicates whether this benchmark applies specifically to institutional-grade investment properties meeting NCREIF/REIT portfolio standards (True) or to the broader market including non-institutional assets (False). Relevant for REIT portfolio NAV/GAV calculations and SEC reporting.',
    `is_primary_benchmark` BOOLEAN COMMENT 'Indicates whether this record is designated as the primary (preferred) benchmark for the given property type, asset class, and submarket combination when multiple sources exist for the same period. True = primary benchmark to be used in appraisal validation; False = secondary/supplemental benchmark.',
    `market_liquidity_rating` STRING COMMENT 'Qualitative assessment of the transaction liquidity in this market segment at the time of the survey (high, moderate, low, illiquid). Informs the reliability weighting of the benchmark and the appropriate discount for illiquidity in investment advisory and REIT portfolio reporting.. Valid values are `high|moderate|low|illiquid`',
    `ncreif_property_index_code` STRING COMMENT 'The NCREIF (National Council of Real Estate Investment Fiduciaries) Property Index segment code corresponding to this benchmarks property type and geographic classification. Enables alignment with NCREIF NPI return benchmarks for institutional investment performance reporting.',
    `noi_psf_high` DECIMAL(18,2) COMMENT 'The upper bound of the surveyed Net Operating Income (NOI) per square foot (PSF) range for this market segment. Used alongside noi_psf_low to bracket NOI assumptions in Argus Enterprise DCF models and appraisal income approach analyses.',
    `noi_psf_low` DECIMAL(18,2) COMMENT 'The lower bound of the surveyed Net Operating Income (NOI) per square foot (PSF) range for this market segment, expressed in the currency per square foot. Used as an input cross-check for DCF models in Argus Enterprise and for validating NOI assumptions in appraisal reports.',
    `sample_size` STRING COMMENT 'The number of transactions, properties, or investor respondents included in the source survey for this specific property type, asset class, and submarket segment. A key indicator of statistical reliability; smaller samples warrant greater caution in appraisal application.',
    `source_organization` STRING COMMENT 'The name of the industry research organization or brokerage firm that published the survey from which this benchmark data was sourced (e.g., CoStar, CBRE, JLL, Cushman & Wakefield, NCREIF, PwC/Korpacz). Governs the credibility weighting applied during appraiser CAP rate selection validation. [ENUM-REF-CANDIDATE: CoStar|CBRE|JLL|Cushman & Wakefield|NCREIF|PwC/Korpacz|Marcus & Millichap|Colliers|Avison Young|Green Street — promote to reference product]',
    `source_report_name` STRING COMMENT 'The formal name of the survey report or publication from which this benchmark data was extracted (e.g., CBRE Cap Rate Survey H1 2024, PwC Real Estate Investor Survey Q3 2024, NCREIF Property Index Q2 2024). Enables traceability back to the original source document for audit and IVSC compliance.',
    `source_report_url` STRING COMMENT 'The URL or digital reference link to the original published survey report. Supports audit trail requirements and allows appraisers to access the primary source document when validating CAP rate selections.',
    `survey_date` DATE COMMENT 'The date on which the market survey or data collection was conducted or published by the source organization. This is the principal real-world event date for this benchmark record, representing when the CAP rate data was captured from the market.',
    `survey_frequency` STRING COMMENT 'The publication cadence of the source survey (quarterly, semi-annual, annual, monthly). Used to determine the expected expiry_date of each benchmark record and to schedule automated refresh workflows in the data pipeline.. Valid values are `quarterly|semi_annual|annual|monthly`',
    `survey_methodology` STRING COMMENT 'Narrative description of the data collection and analysis methodology used by the source organization to derive the CAP rate benchmarks (e.g., transaction-based, investor survey, broker opinion, hedonic regression). Required for IVSC-compliant methodology metadata and appraiser disclosure in appraisal reports.',
    `total_transaction_volume` DECIMAL(18,2) COMMENT 'The aggregate dollar value of all transactions included in the benchmark dataset for this segment and period, expressed in the currency indicated by currency_code. Provides context for the depth and liquidity of the market segment being benchmarked.',
    `transaction_count` STRING COMMENT 'The number of actual closed sale transactions underlying the CAP rate benchmark data for this segment and period, where the source provides transaction-based data. Distinct from sample_size which may include survey respondents. Supports statistical confidence assessment.',
    `trend_basis_points` STRING COMMENT 'The period-over-period change in the midpoint CAP rate expressed in basis points (bps), where 1 bps = 0.01%. Negative values indicate compression; positive values indicate expansion. Provides a precise quantitative measure of market movement to complement the qualitative trend_direction field.',
    `trend_direction` STRING COMMENT 'Directional trend of CAP rates in this market segment relative to the prior survey period. Compressing indicates CAP rates are decreasing (values rising); stable indicates no material change; expanding indicates CAP rates are increasing (values falling). Critical context for investment committee presentations and portfolio NAV/GAV assessments.. Valid values are `compressing|stable|expanding`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this benchmark record was most recently modified, including updates to CAP rate values, status changes, or analyst note revisions. Supports change tracking, data lineage, and SOX audit trail requirements.',
    CONSTRAINT pk_cap_rate_benchmark PRIMARY KEY(`cap_rate_benchmark_id`)
) COMMENT 'Market CAP rate benchmark record by property type, submarket, and asset class sourced from industry surveys. Stores survey date, property type (office, retail, industrial, multifamily, hotel, data center), submarket/MSA, asset class (Class A/B/C), CAP rate range (low, mid, high), source (CoStar, CBRE, JLL, Cushman & Wakefield, NCREIF, PwC/Korpacz), survey methodology, sample size, and trend direction (compressing, stable, expanding). Used to validate appraiser CAP rate selections, support portfolio-level NAV/GAV calculations, and provide market context for investment committee presentations.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`nav_calculation` (
    `nav_calculation_id` BIGINT COMMENT 'Primary key for nav_calculation',
    `assessment_id` BIGINT COMMENT 'Foreign key linking to compliance.assessment. Business justification: NAV calculations for real estate funds require compliance assessments (third-party audits, SEC/AIFMD fair value reviews). nav_calculation has is_audited and third_party_appraiser attributes indicating',
    `asset_id` BIGINT COMMENT 'Foreign key linking to property.asset. Business justification: NAV calculations require per-asset fair value attribution for IFRS 13 and ASC 820 reporting. nav_calculation links to portfolio and fund but not individual assets. Asset-level NAV attribution is requi',
    `cap_rate_benchmark_id` BIGINT COMMENT 'Foreign key linking to valuation.cap_rate_benchmark. Business justification: NAV calculations use weighted average cap rates to derive gross asset value from NOI. The nav_calculation table has a weighted_avg_cap_rate field that should reference the market cap rate benchmark us',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: NAV calculation financial outputs (gross_asset_value, net_asset_value, nav_per_unit, ffo, affo, aum) are currency-denominated. Normalizing the plain currency_code column to a FK is required for multi-',
    `debt_instrument_id` BIGINT COMMENT 'Foreign key linking to finance.debt_instrument. Business justification: NAV calculations net total debt against gross asset value. Linking to the primary debt instrument enables drill-down from NAV to individual loans, supporting REIT debt covenant monitoring and NAV audi',
    `fund_id` BIGINT COMMENT 'Reference to the specific real estate fund (e.g., REIT, private equity fund) for which this NAV calculation is prepared. Supports multi-fund reporting and SEC REIT disclosure requirements.',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: NAV calculations require geographic hierarchy for portfolio geographic attribution in investor reports and regulatory filings. INREV and NCREIF reporting require geographic breakdown of NAV by market/',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: NAV calculations are drawn from a specific accounting ledger (GAAP, IFRS, tax). Fund administrators must know which ledger the NAV figures derive from for audit, regulatory reporting, and investor dis',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to reference.market_segment. Business justification: NAV calculations are strategy-specific; core, value-add, and opportunistic funds use different valuation methodologies, discount rates, and benchmark comparisons. Linking to market_segment enables str',
    `market_survey_id` BIGINT COMMENT 'Foreign key linking to marketing.market_survey. Business justification: NAV calculations for real estate funds use market survey data (vacancy rates, market rents, cap rates) to validate and stress-test appraised values. Fund managers and auditors reference the market sur',
    `noi_statement_id` BIGINT COMMENT 'Foreign key linking to finance.noi_statement. Business justification: NAV calculations use period NOI as a primary input for cap rate-based property valuation. Linking to the authoritative NOI statement enables fund accountants to trace the NOI figure used in NAV to the',
    `portfolio_id` BIGINT COMMENT 'Reference to the investment portfolio or fund for which this NAV/GAV calculation is performed. Links to the portfolio or fund master record in MRI Software or Argus Enterprise.',
    `prior_calculation_nav_calculation_id` BIGINT COMMENT 'Self-referencing identifier pointing to the immediately preceding NAV calculation record for this portfolio/fund. Enables calculation chain traceability and period-over-period reconciliation.',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: NAV calculations for REITs and open-end funds are segmented by property type for portfolio attribution and investor reporting. INREV, NCREIF, and SEC reporting frameworks require property type attribu',
    `reporting_period_id` BIGINT COMMENT 'Foreign key linking to finance.reporting_period. Business justification: NAV calculations are produced on a defined reporting schedule (monthly, quarterly, annually). The reporting_period governs when NAV is published for investor reporting, REIT compliance, and fund admin',
    `affo` DECIMAL(18,2) COMMENT 'Adjusted Funds From Operations (AFFO) for the reporting period, representing FFO adjusted for recurring capital expenditures, straight-line rent adjustments, and other non-cash items. Considered a more accurate proxy for distributable cash flow than FFO.',
    `approval_date` DATE COMMENT 'The date on which this NAV/GAV calculation was formally approved by the designated reviewer or investment committee. Supports SOX control documentation and audit trail.',
    `argus_model_reference` STRING COMMENT 'Reference identifier or file path to the Argus Enterprise cash flow model(s) used as the source for property valuations feeding into this NAV/GAV calculation. Supports audit traceability back to the originating valuation model.',
    `aum` DECIMAL(18,2) COMMENT 'Total Assets Under Management (AUM) for the fund or portfolio as of the calculation date, which may differ from GAV by including non-real-estate assets, cash, and receivables. Used in investment advisory fee calculations and investor reporting.',
    `calculation_date` DATE COMMENT 'The as-of date for which the NAV and GAV are calculated. This is the principal business event date — the valuation reference point used in investor reports, REIT filings, and ASC 820 fair value disclosures.',
    `calculation_number` STRING COMMENT 'Human-readable, externally referenceable business identifier for this NAV/GAV calculation run (e.g., NAV-2024-000123). Used in investor reports, SEC filings, and audit trails to uniquely reference a specific calculation event.. Valid values are `^NAV-[0-9]{4}-[0-9]{6}$`',
    `calculation_status` STRING COMMENT 'Current lifecycle state of the NAV/GAV calculation record. Controls workflow from initial preparation through review, approval, and publication to investors or regulators. Superseded indicates a revised calculation replaced this one.. Valid values are `draft|under_review|approved|published|superseded|voided`',
    `capex_reserve` DECIMAL(18,2) COMMENT 'Estimated capital expenditure (CAPEX) reserve set aside for future property improvements, TI (Tenant Improvements), and major maintenance across the portfolio. Deducted in AFFO calculation and considered in NAV adjustments.',
    `cash_and_equivalents` DECIMAL(18,2) COMMENT 'Total cash and cash equivalent balances held at the portfolio or fund level as of the calculation date. Included in the NAV bridge as a non-real-estate asset component.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this NAV calculation record was first created in the system. Supports audit trail, SOX control documentation, and data lineage tracking in the Databricks Silver layer.',
    `discount_rate` DECIMAL(18,2) COMMENT 'The discount rate (required rate of return) applied in DCF-based property valuations feeding into this NAV calculation. Reflects risk-adjusted cost of capital for the portfolio. Applicable when valuation_methodology is dcf or blended.',
    `fair_value_hierarchy_level` STRING COMMENT 'ASC 820 / IFRS 13 fair value hierarchy classification for the inputs used in this NAV calculation. Level 1 = quoted market prices; Level 2 = observable inputs; Level 3 = unobservable inputs (most common for real estate). Required for SEC and financial statement disclosures.. Valid values are `Level 1|Level 2|Level 3`',
    `ffo` DECIMAL(18,2) COMMENT 'Funds From Operations (FFO) for the reporting period, calculated per NAREIT definition as net income plus real estate depreciation and amortization, excluding gains/losses on property sales. Standard REIT performance metric reported to investors and the SEC.',
    `gross_asset_value` DECIMAL(18,2) COMMENT 'Total Gross Asset Value (GAV) of the portfolio as of the calculation date, representing the sum of all property market values before deducting debt and liabilities. Core output of the NAV model used in REIT reporting, investor communications, and ASC 820 fair value disclosures.',
    `is_audited` BOOLEAN COMMENT 'Indicates whether this NAV/GAV calculation has been subject to external audit review (True) or is an unaudited management estimate (False). Relevant for annual REIT financial statement audits and SEC filings.',
    `is_published` BOOLEAN COMMENT 'Indicates whether this NAV calculation has been formally published and communicated to investors or regulators (True) or remains an internal working estimate (False). Controls investor disclosure workflow.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this NAV calculation record. Supports change tracking, SOX audit trail, and incremental data processing in the Databricks Silver layer.',
    `ltv_ratio` DECIMAL(18,2) COMMENT 'Portfolio-level Loan-to-Value (LTV) ratio, calculated as total debt outstanding divided by GAV. Key leverage metric monitored by lenders, investors, and rating agencies for CMBS and REIT credit analysis.',
    `methodology_notes` STRING COMMENT 'Free-text narrative describing key assumptions, methodology choices, significant judgments, and any departures from standard methodology applied in this NAV/GAV calculation. Required for FASB ASC 820 Level 3 disclosure and investor transparency.',
    `nav_change` DECIMAL(18,2) COMMENT 'Absolute change in NAV from the prior period to the current calculation date (current NAV minus prior NAV). Supports period-over-period performance reporting to investors and the board.',
    `nav_per_unit` DECIMAL(18,2) COMMENT 'NAV divided by total units or shares outstanding, representing the per-unit intrinsic value of the fund or REIT. Key metric for investor reporting, unit pricing, and performance benchmarking.',
    `net_asset_value` DECIMAL(18,2) COMMENT 'Net Asset Value (NAV) of the portfolio or fund, calculated as GAV minus total debt outstanding minus other liabilities. The primary output metric used in REIT investor reporting, unit pricing, and SEC fair value disclosures.',
    `noi_total` DECIMAL(18,2) COMMENT 'Aggregate Net Operating Income (NOI) across all properties included in this NAV calculation, representing total effective gross income minus operating expenses before debt service. Primary input to direct capitalization and DCF valuation methodologies.',
    `prior_nav` DECIMAL(18,2) COMMENT 'NAV from the immediately preceding calculation period, used to compute period-over-period NAV change and growth rate for investor reporting and performance attribution.',
    `property_count` STRING COMMENT 'Total count of properties included in this NAV/GAV calculation. Provides a completeness check and supports reconciliation against the portfolio property register in Argus Enterprise or MRI Software.',
    `publication_date` DATE COMMENT 'The date on which this NAV calculation was formally published and made available to investors or filed with regulators. Null if not yet published.',
    `reporting_period` STRING COMMENT 'The financial reporting period this NAV calculation corresponds to (e.g., Q1, Q2, Q3, Q4, Annual, Monthly). Aligns the calculation with the funds financial reporting calendar for investor and SEC reporting.. Valid values are `Q1|Q2|Q3|Q4|Annual|Monthly`',
    `reporting_year` STRING COMMENT 'The fiscal or calendar year associated with this NAV calculation (e.g., 2024). Used in conjunction with reporting_period to uniquely identify the reporting cycle.',
    `straight_line_rent_adjustment` DECIMAL(18,2) COMMENT 'Non-cash straight-line rent adjustment applied to AFFO, representing the difference between contractual rent escalations recognized on a straight-line basis under ASC 842 and actual cash rent received. Standard REIT AFFO adjustment.',
    `third_party_appraiser` STRING COMMENT 'Name of the external appraisal firm or certified appraiser (MAI designation, Appraisal Institute member) engaged to provide independent property valuations used in this NAV calculation. Required when valuation_methodology includes third-party appraisal.',
    `total_debt_outstanding` DECIMAL(18,2) COMMENT 'Aggregate outstanding debt balance (mortgages, credit facilities, CMBS, and other borrowings) secured against or attributable to the portfolio as of the calculation date. Deducted from GAV to arrive at NAV.',
    `units_outstanding` DECIMAL(18,2) COMMENT 'Total number of fund units or REIT shares outstanding as of the calculation date. Used as the denominator to compute NAV per unit/share for investor reporting and unit pricing.',
    `valuation_methodology` STRING COMMENT 'The primary methodology used to determine property market values feeding into the GAV calculation. Options include direct capitalization (applying a CAP rate to NOI), Discounted Cash Flow (DCF), third-party appraisal, a blended approach, or a proprietary NAV model. Aligns with IVSC and FASB ASC 820 fair value hierarchy.. Valid values are `direct_capitalization|dcf|third_party_appraisal|blended|nav_model`',
    `weighted_avg_cap_rate` DECIMAL(18,2) COMMENT 'Portfolio-level weighted average CAP rate (Capitalization Rate) applied across all properties in the NAV calculation, weighted by property value. Used to validate the implied GAV against market benchmarks and support investor reporting.',
    CONSTRAINT pk_nav_calculation PRIMARY KEY(`nav_calculation_id`)
) COMMENT 'Net Asset Value (NAV) and Gross Asset Value (GAV) calculation record at the portfolio or fund level. Stores calculation date, portfolio/fund reference, total GAV (sum of market values), total debt outstanding, NAV (GAV minus debt), NAV per unit/share, AFFO adjustment, FFO, methodology (direct capitalization, DCF, third-party appraisal blend), number of properties included, and calculation preparer. Supports REIT financial reporting (SEC), investor reporting, and ASC 820 fair value disclosures.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`tax_assessment` (
    `tax_assessment_id` BIGINT COMMENT 'Primary key for tax_assessment',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: Tax assessments express tax_psf (tax per square foot/meter); the area UOM reference ensures consistent measurement standards across jurisdictions. Multi-state portfolio tax management requires UOM sta',
    `assessment_id` BIGINT COMMENT 'Foreign key linking to compliance.assessment. Business justification: Tax assessment appeals frequently reference compliance assessments (environmental findings, building condition assessments) that support adjusted value claims. Tax counsel and assessors use compliance',
    `asset_id` BIGINT COMMENT 'Reference to the assessed property in the property master data product. Links the tax assessment to the specific real estate asset.',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: Annual property tax assessments are a key input to the finance budget (property_tax_expense line). Budget vs. actual variance analysis for tax expense requires linking the assessed tax to the budget r',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: Tax assessors classify buildings by class (A/B/C) to determine assessment methodology and select comparable properties for the sales comparison approach in mass appraisal. Building class affects the a',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Tax assessments separately value land and improvements (assessed_improvement_value). The improvement value is building-specific. Assessors issue building-level improvement assessments. Linking to buil',
    `construction_type_id` BIGINT COMMENT 'Foreign key linking to reference.construction_type. Business justification: Tax assessors use construction type to determine replacement cost and depreciation in the cost approach to mass appraisal. ISO construction class codes are used by assessors to set insurance class and',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Property tax expense is tracked and allocated through cost centers. Tax assessments drive the property_tax_expense line in NOI statements and must be coded to a cost center for GL posting and budget v',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Tax assessment financial figures (assessed_land_value, total_assessed_value, gross_annual_tax, net_annual_tax) are currency-denominated. Normalizing the plain currency_code column to a FK supports mul',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: Tax assessors issue assessments on properties under active construction. Development teams track these to manage tax liability in project budgets and appeal assessments on partially-completed building',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: Tax assessments are jurisdiction-specific; the taxing_jurisdiction_name and jurisdiction_code plain columns are denormalized geographic hierarchy fields. Normalizing to a FK enables jurisdiction-level',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction. Business justification: Tax assessments are issued by specific jurisdictions; appeal deadlines, filing requirements, and penalty authority are all jurisdiction-governed. taxing_jurisdiction_name and jurisdiction_code are den',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Tax assessments and related tax expense postings are recorded in a specific ledger (GAAP vs. tax basis). Linking tax_assessment to ledger supports tax basis vs. book basis reconciliation, a standard r',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to property.parcel. Business justification: Tax assessments are issued by jurisdiction against a specific parcel (APN). tax_assessment.parcel_number is denormalized from parcel. The parcel record is the authoritative source for APN, tax_distric',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Tax assessors use building permit records to identify permitted improvements and assess their value. Unpermitted improvements are assessed differently or excluded. Linking tax_assessment to the govern',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to reference.property_type. Business justification: Tax assessments classify properties by property type which determines the assessment methodology, millage rate, and exemption eligibility. Assessors use property type as the primary classification for',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Property tax assessments are governed by specific regulatory obligations (state assessment statutes, appeal procedures, disclosure requirements). Compliance teams track which regulatory obligation gov',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: Tax assessments classify space use type for property tax classification and exemption eligibility. Mixed-use properties require space use type breakdown for apportioning assessed value between commerc',
    `transaction_type_id` BIGINT COMMENT 'Foreign key linking to reference.transaction_type. Business justification: Tax assessments are triggered by specific transaction types (sale, transfer, new construction, renovation) which determines the reassessment trigger and transfer tax applicability. Many jurisdictions ',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Condominium and co-op units receive individual tax assessments and tax bills. tax_assessment links to asset, building, and parcel but not unit. Unit-level tax assessment tracking is required for condo',
    `zoning_code_id` BIGINT COMMENT 'Foreign key linking to reference.zoning_code. Business justification: Tax assessments reference zoning code for property classification and exemption eligibility determination. Assessors use zoning to classify properties for agricultural, commercial, or residential tax ',
    `abatement_amount` DECIMAL(18,2) COMMENT 'Dollar value of any tax abatement granted by the taxing authority (e.g., development incentive abatement, payment-in-lieu-of-taxes (PILOT) arrangement). Distinct from exemptions; abatements are typically time-limited incentives tied to development agreements.',
    `abatement_expiry_date` DATE COMMENT 'Date on which any tax abatement arrangement expires, after which the full tax liability applies. Critical for long-term cash flow modeling in Argus Enterprise and investment underwriting — abatement burn-off materially impacts NOI (Net Operating Income) projections.',
    `appeal_deadline` DATE COMMENT 'Statutory deadline by which a formal appeal of the assessed value must be filed with the taxing authority. Critical compliance date tracked in Yardi Voyager and DocuSign CLM for deadline management.',
    `appeal_filed_date` DATE COMMENT 'Date on which the formal appeal was submitted to the taxing authority or appeals board. Null if no appeal has been filed. Used for tracking appeal timelines and legal deadlines.',
    `appeal_resolution_date` DATE COMMENT 'Date on which the taxing authority or appeals board issued a final decision on the appeal. Null if appeal is still pending. Triggers revised tax liability calculations.',
    `appeal_settled_value` DECIMAL(18,2) COMMENT 'Final assessed value agreed upon or ordered as a result of the appeal process. Null if appeal is pending or not filed. Replaces the original assessed value for tax liability calculation upon resolution.',
    `appeal_status` STRING COMMENT 'Current status of any formal appeal filed against this assessment. Tracks the appeal lifecycle from filing through final determination. Informs contingent liability disclosures under FASB ASC 450. [ENUM-REF-CANDIDATE: not_appealed|appeal_filed|hearing_scheduled|decision_pending|appeal_granted|appeal_denied — promote to reference product]. Valid values are `not_appealed|appeal_filed|hearing_scheduled|decision_pending|appeal_granted|appeal_denied`',
    `appeal_target_value` DECIMAL(18,2) COMMENT 'The assessed value the property owner is seeking through the appeal process. Represents the owners position on fair assessed value, typically supported by an independent appraisal or BPO (Broker Price Opinion). Used to quantify potential tax savings from a successful appeal.',
    `argus_model_reference` STRING COMMENT 'Reference identifier for the Argus Enterprise cash flow model in which this tax assessments OPEX (Operating Expenditure) is incorporated. Enables traceability between the assessed tax expense and the DCF (Discounted Cash Flow) valuation model.',
    `assessed_improvement_value` DECIMAL(18,2) COMMENT 'Dollar value assigned by the taxing authority to the building and structural improvements on the property, exclusive of land. Drives depreciation analysis and CAPEX (Capital Expenditure) planning in Argus Enterprise models.',
    `assessed_land_value` DECIMAL(18,2) COMMENT 'Dollar value assigned by the taxing authority to the land component of the property, exclusive of improvements. Used in land vs. improvement allocation analysis and depreciation studies. Sourced from Yardi Voyager Fixed Assets and Argus Enterprise.',
    `assessment_ratio` DECIMAL(18,2) COMMENT 'The ratio of assessed value to estimated market value as applied by the taxing jurisdiction (e.g., 0.80 = 80% of market value). Varies by jurisdiction and property class. Used to back-calculate implied market value from assessed value for investment analysis.',
    `assessment_status` STRING COMMENT 'Current lifecycle state of the tax assessment record. Tracks progression from preliminary notice through certification, appeal, and final determination. Drives workflow in Yardi Voyager property accounting.. Valid values are `preliminary|certified|appealed|revised|final`',
    `assessment_year` STRING COMMENT 'The tax year (calendar year) for which this assessment applies. Drives annual property tax expense calculations and year-over-year valuation trend analysis. Critical for NOI (Net Operating Income) OPEX reporting.',
    `assessor_contact` STRING COMMENT 'Phone number or contact detail for the assessors office. Used for inquiry and appeal coordination. Classified as confidential organizational contact data.',
    `assessor_name` STRING COMMENT 'Name of the government assessor or assessment office responsible for this assessment. Used for correspondence, appeal filings, and audit documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this tax assessment record was first created in the Silver Layer lakehouse. Supports data lineage, audit trail, and SOX (Sarbanes-Oxley Act) financial controls.',
    `effective_tax_rate` DECIMAL(18,2) COMMENT 'The effective property tax rate expressed as a decimal percentage of the total assessed value (e.g., 0.0125 = 1.25%). Accounts for all applicable levies across overlapping jurisdictions. Used in NOI (Net Operating Income) modeling and CAP Rate (Capitalization Rate) analysis in Argus Enterprise.',
    `exemption_amount` DECIMAL(18,2) COMMENT 'Total dollar value of tax exemptions applied to this assessment (e.g., homestead exemption, REIT (Real Estate Investment Trust) exemption, historic preservation, enterprise zone). Reduces the taxable assessed value or gross tax liability.',
    `exemption_type` STRING COMMENT 'Classification of the primary tax exemption applied to this assessment. Determines eligibility criteria and renewal requirements. [ENUM-REF-CANDIDATE: homestead|senior|veteran|nonprofit|historic|enterprise_zone|reit — promote to reference product]',
    `gross_annual_tax` DECIMAL(18,2) COMMENT 'Gross annual property tax liability before application of any exemptions, abatements, or credits. Computed from assessed value and millage rate. Key OPEX (Operating Expenditure) component in NOI (Net Operating Income) calculations and Argus Enterprise cash flow models.',
    `implied_market_value` DECIMAL(18,2) COMMENT 'Estimated market value implied by the taxing authoritys assessment, calculated as total assessed value divided by the assessment ratio. Provides a reference point for comparing assessed value against independent appraisals and Argus Enterprise DCF (Discounted Cash Flow) valuations.',
    `installment_count` STRING COMMENT 'Number of installment payments into which the annual tax liability is divided (e.g., 1 = lump sum, 2 = semi-annual, 4 = quarterly). Determines AP (Accounts Payable) payment scheduling and cash flow timing in Yardi Voyager.',
    `is_nnn_tenant_recoverable` BOOLEAN COMMENT 'Indicates whether the property tax expense is recoverable from tenants under NNN (Triple Net Lease) or modified gross lease structures. True = tax is passed through to tenants as a CAM (Common Area Maintenance) or operating expense recovery; False = landlord bears the tax expense. Critical for EGI (Effective Gross Income) and NOI (Net Operating Income) modeling.',
    `jurisdiction_type` STRING COMMENT 'Classification of the taxing authority by governmental level. Properties may have multiple overlapping jurisdictions; this field identifies the type for each assessment record.. Valid values are `county|municipal|state|special_district|school_district`',
    `millage_rate` DECIMAL(18,2) COMMENT 'The tax rate expressed in mills (dollars of tax per $1,000 of assessed value) levied by the taxing jurisdiction. Multiplied by the assessed value to compute the gross annual tax liability before exemptions.',
    `net_annual_tax` DECIMAL(18,2) COMMENT 'Net annual property tax liability after deducting all exemptions, abatements, and credits from the gross tax. This is the actual cash tax expense recorded in Yardi Voyager GL (General Ledger) and reported as a property OPEX (Operating Expenditure) line item in NOI (Net Operating Income) statements.',
    `notice_date` DATE COMMENT 'Date the taxing authority issued the official assessment notice to the property owner. Establishes the start of the appeal window and triggers internal review processes.',
    `payment_due_date` DATE COMMENT 'Date by which the property tax payment must be remitted to the taxing authority to avoid penalties and interest. Drives AP (Accounts Payable) scheduling in Yardi Voyager and cash flow planning.',
    `prior_year_assessed_value` DECIMAL(18,2) COMMENT 'Total assessed value from the immediately preceding tax year. Enables year-over-year change analysis and supports appeal arguments based on disproportionate value increases. Used in Argus Enterprise cash flow modeling.',
    `property_class_code` STRING COMMENT 'Assessors classification code for the property type (e.g., residential, commercial, industrial, agricultural). Determines applicable assessment methodology, exemption eligibility, and tax rate schedule.',
    `review_notes` STRING COMMENT 'Free-text notes entered by the internal reviewer documenting assessment analysis, appeal rationale, comparable evidence, or instructions for the AP (Accounts Payable) team. Supports audit trail requirements under SOX (Sarbanes-Oxley Act).',
    `tax_bill_number` STRING COMMENT 'Official tax bill number issued by the taxing authority for the annual tax payment. Used for AP (Accounts Payable) invoice matching in Yardi Voyager and SAP S/4HANA to ensure accurate tax remittance.',
    `tax_psf` DECIMAL(18,2) COMMENT 'Annual net property tax liability expressed on a per-square-foot (PSF) basis. Enables benchmarking across properties of different sizes and is a standard metric in NNN (Triple Net Lease) lease analysis and CAM (Common Area Maintenance) reconciliations.',
    `total_assessed_value` DECIMAL(18,2) COMMENT 'Total assessed value of the property as determined by the taxing authority, representing the sum of assessed land value and assessed improvement value. This is the ad valorem tax base and is typically distinct from market value. Key input to NOI (Net Operating Income) OPEX calculations.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this tax assessment record was last modified in the Silver Layer lakehouse. Tracks revisions from appeal outcomes, value corrections, or payment status updates. Required for SOX (Sarbanes-Oxley Act) audit trail.',
    `yardi_property_code` STRING COMMENT 'Property code as assigned in Yardi Voyager, the system of record for property accounting and tax expense tracking. Enables direct reconciliation between this Silver Layer record and the source systems tax ledger entries.',
    CONSTRAINT pk_tax_assessment PRIMARY KEY(`tax_assessment_id`)
) COMMENT 'Property tax assessment record capturing the assessed value assigned by the taxing authority for ad valorem tax purposes. Stores assessment year, assessed land value, assessed improvement value, total assessed value, assessment ratio, effective tax rate, annual tax liability, taxing jurisdiction, assessment notice date, appeal deadline, and appeal status. Distinct from market value appraisals — assessed value often differs materially from market value and drives property tax expense (a key OPEX component in NOI calculations).';

CREATE OR REPLACE TABLE `real_estate_ecm`.`valuation`.`nav_appraisal_input` (
    `nav_appraisal_input_id` BIGINT COMMENT 'Primary key for the nav_appraisal_input association',
    `appraisal_id` BIGINT COMMENT 'Foreign key linking to the formal property appraisal engagement whose concluded value was used as input to the NAV calculation',
    `nav_calculation_id` BIGINT COMMENT 'Foreign key linking to the NAV/GAV calculation record that consumed this appraisal as an input',
    `appraisal_coverage_flag` BOOLEAN COMMENT 'Indicates whether this appraisal input qualifies as an independent third-party appraisal for the purpose of calculating the portfolio-level appraisal_coverage_pct on the NAV calculation. Internal desk valuations or stale appraisals beyond the staleness threshold would be flagged FALSE. Explicitly identified in detection phase relationship data and directly drives the nav_calculation.appraisal_coverage_pct aggregate.',
    `appraisal_coverage_pct` DECIMAL(18,2) COMMENT 'Percentage of the portfolio GAV supported by independent third-party appraisals in this calculation cycle (e.g., 75.00 means 75% of GAV is appraiser-supported). Relevant for FASB ASC 820 Level 3 disclosure and investor transparency. [Moved from nav_calculation: This aggregate percentage on nav_calculation is DERIVED from the individual appraisal_coverage_flag values on each nav_appraisal_input record. It is a computed rollup of the association data, not an independently maintained attribute of the NAV calculation itself. It should be computed from the association table rather than stored redundantly on nav_calculation. If retained on nav_calculation for reporting performance, it should be treated as a derived/materialized field, not a source-of-truth attribute.]',
    `contribution_value` DECIMAL(18,2) COMMENT 'The absolute dollar amount this appraisals concluded market value contributes to the total Gross Asset Value (GAV) in the NAV calculation. May differ from the appraisals full concluded value if a partial interest or ownership percentage is applied. Explicitly identified in detection phase relationship data.',
    `valuation_effective_date` DATE COMMENT 'The as-of date of the appraisal value used in this NAV calculation. May differ from the appraisal report date (e.g., a Sept 30 appraisal may be carried forward and used in a Dec 31 NAV calculation under a recertification). Explicitly identified in detection phase relationship data.',
    `weight_pct` DECIMAL(18,2) COMMENT 'The proportional weight (as a percentage of total GAV) assigned to this appraisals value within the NAV calculation. Reflects the relative size of the appraised property within the portfolio. Explicitly identified in detection phase relationship data.',
    CONSTRAINT pk_nav_appraisal_input PRIMARY KEY(`nav_appraisal_input_id`)
) COMMENT 'This association product represents the formal input record (Contract/Schedule) between a NAV calculation and a constituent appraisal. It captures which appraisal values were used as inputs to a specific NAV/GAV calculation, at what proportional weight, and what dollar contribution each appraisal made to the total GAV. Each record links one nav_calculation to one appraisal and carries attributes that exist only in the context of this specific input relationship — the weight, contribution, effective date used, and coverage flag. This is the operational record that fund accountants and valuation teams manage to support REIT financial reporting, SEC disclosures, and ASC 820 fair value documentation.. Existence Justification: In real estate fund management, NAV calculations are formal periodic exercises (monthly, quarterly, annually) that aggregate appraised values across all portfolio properties — a single NAV calculation genuinely consumes many appraisals as inputs. Conversely, a single appraisal (e.g., a Q3 independent appraisal of a Class A office building) feeds into multiple NAV calculations over time: the current periods fund-level NAV, a prior-period restatement, and potentially multiple fund structures that hold the same asset. This is an operationally managed relationship — fund accountants and valuation teams actively track which appraisals were used in which NAV calculation, at what weight, and what value contribution each appraisal made.';

